}

export type RepetitionType = 'WEEKLY' | 'DATE' | 'INTERVAL';

export interface VisitRepetition {
  type: RepetitionType;
  daysOfWeek?: number[]; // 0=Sunday, 1=Monday...
  specificDate?: string; // YYYY-MM-DD
  intervalStart?: string; // YYYY-MM-DD
  intervalDays?: number;
}

