  // Reload Plan Button Handler
  const handleReloadPlan = () => {
      if (confirm(t.msgConfirmPlanReload)) {
          const dailyRoute = loadDailyPlan(clients);
          const cleared = clearCalculation(dailyRoute);
          setVisits(reindexVisits(cleared));
          setCompilationInfo(t.msgPlanReloaded);
          setTimeout(() => setCompilationInfo(null), 3000);
      }
  };

  const handleImportClientsExcel = async (file: File) => {
      try {
          const parsed = await parseVisitsExcel(file);
          // Convert parsed visits to Clients
          const newClients: Client[] = await Promise.all(parsed.map(async p => {
             const check = await checkAddress(p.address);
             return {
                 id: uuid(),
                 name: p.name,
                 surname: p.surname,
                 address: p.address,
                 defaultDuration: p.visitDuration,
                 isAddressValid: check.isValid,
                 visitRepetition: { type: 'WEEKLY', daysOfWeek: [] } // Default to none/manual schedule
             };
          }));
          setClients(prev => [...prev, ...newClients]);
          console.log(`${t.msgImportSuccess} (${newClients.length})`);
      } catch (e: any) {
          console.error(e);
          alert(e.message);
      }
  };


  const saveSettings = (newSettings: AppSettings) => {
      if (newSettings.startAddress !== settings.startAddress || newSettings.currentOdometer !== settings.currentOdometer || newSettings.departureTime !== settings.departureTime) {
          const cleared = clearCalculation(visits);
          setVisits(cleared);
      }
      if (newSettings.googleApiKey !== settings.googleApiKey) {
          if (newSettings.googleApiKey) {
              setRuntimeApiKey(newSettings.googleApiKey);
              loadGoogleMapsScript(newSettings.googleApiKey)
                .then(() => setIsApiReady(true))
                .catch(e => { console.error(e); setIsApiReady(false); });
          } else { setRuntimeApiKey(""); setIsApiReady(false); }
      }
      if (newSettings.cacheExpirationDays && newSettings.cacheExpirationDays !== settings.cacheExpirationDays) {
          setCacheExpirationDays(newSettings.cacheExpirationDays);
      }
      setSettings(newSettings);
  };

  const handleDeleteClick = () => {
    if (deleteConfirming) {
        const remainingVisits = visits.filter(v => !selectedIds.has(v.id));
        const cleared = clearCalculation(remainingVisits);
        setVisits(reindexVisits(cleared));
        setSelectedIds(new Set());
        setDeleteConfirming(false);
        console.log("Bulk delete performed.");
    } else {
        setDeleteConfirming(true);
        setTimeout(() => setDeleteConfirming(false), 4000);
    }
  };

  const handleDeleteRow = (id: string) => {
      const remaining = visits.filter(v => v.id !== id);
      const cleared = clearCalculation(remaining);
      setVisits(reindexVisits(cleared));
      if (selectedIds.has(id)) {
          const newSelected = new Set(selectedIds);
          newSelected.delete(id);
          setSelectedIds(newSelected);
      }
      console.log(`Visit ${id} deleted.`);
  };

  const handleExcelUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
      const parsed = await parseVisitsExcel(file);
      await processAndAddVisits(parsed);
    } catch (err: any) { console.error(`${t.msgImportFail}:`, err.message); } 
    finally { if (fileInputRef.current) fileInputRef.current.value = ''; }
  };

  const handleLoadSampleData = async (data: any[]) => {
      try {
          const formatted = data.map(d => ({ name: d.name, surname: d.surname, address: d.address, order: d.order, visitDuration: d.visitDuration }));
          await processAndAddVisits(formatted);
      } catch (err: any) { console.error("Sample Load Failed:", err.message); }
  };

  const handleLoadSavedRoute = (route: SavedRoute) => {
    setVisits(route.visits);
    if (route.startTrip) setStartTrip(route.startTrip);
    if (route.returnTrip) setReturnTrip(route.returnTrip);
    console.log(`Route "${route.name}" loaded manually.`);
  };

  const processAndAddVisits = async (newRawVisits: Omit<Visit, 'id'>[]) => {
      let newVisits = newRawVisits.map(v => ({ ...v, id: uuid(), isSkipped: false }));
      const validatedVisits = await Promise.all(newVisits.map(async (v) => {
          const check = await checkAddress(v.address);
          return { ...v, address: v.address, isAddressValid: check.isValid };
      }));
      const combined = [...visits, ...validatedVisits];
      const sorted = combined.sort((a, b) => a.order - b.order);
      const cleared = clearCalculation(sorted);
      setVisits(reindexVisits(cleared));
      console.log(`${t.msgImportSuccess} (${validatedVisits.length})`);
  };

  const handleValidateAll = async () => {
      if (!isApiReady) return;
      if (visits.length === 0) return;
      setCalcStatus(CalculationStatus.VALIDATING);
      setErrorMsg(null);
      const total = visits.length;
      const newVisits = [...visits];
      try {
          for (let i = 0; i < newVisits.length; i++) {
              const v = newVisits[i];
              setProgress({ current: i + 1, total, message: `${t.msgValidating} ${v.surname}...` });
              const res = await checkAddress(v.address);
              newVisits[i] = { ...v, isAddressValid: res.isValid };
              await sleep(20); 
          }
          setVisits(newVisits);
          console.log(`${t.msgValidationComplete} (${total})`);
      } catch (err: any) { console.error(err); setErrorMsg(err.message); } 
      finally { setCalcStatus(CalculationStatus.IDLE); }
  };

  const runCalculation = async (visitsOverride?: Visit[], commitOdometer: boolean = true) => {
    if (!isApiReady) return;
    const sourceVisits = visitsOverride || visits;
    const activeVisits = sourceVisits.filter(v => !v.isSkipped);
    if (activeVisits.length === 0) return;
    if (!settings.startAddress) return;

    setCalcStatus(CalculationStatus.VALIDATING);
    setErrorMsg(null);
    setStartTrip(null);
    setReturnTrip(null);

    const processingAllVisits = [...sourceVisits];
    let currentOdo = settings.currentOdometer;
    let currentLoc = settings.startAddress;
    let returnDest = settings.startAddress; 
    let currentClock = settings.departureTime || "08:00:00";

    const initialStartData: StartTrip = { address: settings.startAddress, odometer: settings.currentOdometer };
    const totalSteps = activeVisits.length + (settings.isStrictMode ? activeVisits.length + 1 : 1); 
    let stepCount = 0;
    const updateProgress = (msg: string) => { stepCount++; setProgress({ current: stepCount, total: totalSteps, message: msg }); };

    try {
      if (settings.isStrictMode) {
        if (!settings.isStartValid) {
            updateProgress(`${t.msgValidating} START...`);
            const validStart = await validateAddressStrict(settings.startAddress);
            currentLoc = validStart;
            returnDest = validStart;
        }
        for (let i = 0; i < processingAllVisits.length; i++) {
          if (processingAllVisits[i].isSkipped) continue;
          const v = processingAllVisits[i];
          if (!v.isAddressValid) {
             updateProgress(`${t.msgValidating} ${v.surname}...`);
             await validateAddressStrict(v.address); 
             processingAllVisits[i].isAddressValid = true; 
          }
        }
      }

      setStartTrip(initialStartData);
      setCalcStatus(CalculationStatus.ROUTING);

      for (let i = 0; i < processingAllVisits.length; i++) {
        if (processingAllVisits[i].isSkipped) continue;
        const visit = processingAllVisits[i];
        updateProgress(`${t.msgRouting} ${visit.surname}...`);
        const routeDest = visit.address;
        const { distanceKm, durationSeconds } = await getRouteData(currentLoc, routeDest);
        const roundedDist = commercialRound(distanceKm);
        currentOdo += roundedDist;
        const arrivalTime = addSecondsToTime(currentClock, durationSeconds);
        const visitDurationSeconds = (visit.visitDuration || 0) * 60;
        currentClock = addSecondsToTime(arrivalTime, visitDurationSeconds);
        processingAllVisits[i].segmentDistance = roundedDist;
        processingAllVisits[i].exactDistanceKm = distanceKm; 
        processingAllVisits[i].segmentDuration = durationSeconds;
        processingAllVisits[i].arrivalTime = arrivalTime;
        if (commitOdometer) processingAllVisits[i].totalOdometer = currentOdo;
        else processingAllVisits[i].totalOdometer = undefined;
        setVisits([...processingAllVisits]); 
        currentLoc = routeDest;
        await sleep(50);
      }

      updateProgress(t.msgCalcReturn);
      const { distanceKm: returnDist, durationSeconds: returnDur } = await getRouteData(currentLoc, returnDest);
      const roundedReturn = commercialRound(returnDist);
      currentOdo += roundedReturn;
      const returnArrivalTime = addSecondsToTime(currentClock, returnDur);

      setReturnTrip({ address: settings.startAddress, segmentDistance: roundedReturn, exactDistanceKm: returnDist, segmentDuration: returnDur, arrivalTime: returnArrivalTime, totalOdometer: commitOdometer ? currentOdo : undefined });
      setCalcStatus(CalculationStatus.COMPLETE);
      if (commitOdometer) setSettings(prev => ({ ...prev, currentOdometer: currentOdo }));
      console.log("Route calculation completed successfully.");
    } catch (err: any) { console.error(err); setErrorMsg(err.message || "An unknown error occurred during calculation."); setCalcStatus(CalculationStatus.ERROR); setStartTrip(null); }
  };

  const handleOptimizeRoute = async () => {
      if (!isApiReady) return;
      const activeVisits = visits.filter(v => !v.isSkipped);
      if (activeVisits.length < 2) return;
      if (!settings.startAddress) return;

      setCalcStatus(CalculationStatus.ROUTING);
      setErrorMsg(null);
      setProgress({ current: 0, total: 100, message: 'Checking cached distances...' });

      try {
          const allAddresses = [settings.startAddress, ...activeVisits.map(v => v.address)];
          await ensureMatrixData(allAddresses, (msg) => { setProgress(prev => ({ ...prev, message: msg })); });
          setProgress({ current: 90, total: 100, message: 'Solving TSP...' });
          await sleep(100);
          const optimizedActive = solveTSP(settings.startAddress, activeVisits);
          const skippedVisits = visits.filter(v => v.isSkipped);
          const newOrder = [...optimizedActive, ...skippedVisits];
          const reindexed = reindexVisits(clearCalculation(newOrder));
          setVisits(reindexed);
          await runCalculation(reindexed, false);
          console.log("Route optimized successfully.");
      } catch (err: any) { console.error(err); setErrorMsg(`${t.msgOptFail}: ${err.message}`); setCalcStatus(CalculationStatus.ERROR); }
  };

  const getProgressWidth = () => { if (progress.total === 0) return 0; return Math.min(100, Math.floor((progress.current / progress.total) * 100)); };
  const canVisualize = !!startTrip && visits.some(v => !v.isSkipped && v.segmentDistance !== undefined);
  const shouldDisableActions = settings.isStrictMode && visits.some(v => !v.isSkipped && v.isAddressValid === false);

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 p-4 md:p-8 transition-colors duration-200 font-sans">
      <div className="max-w-screen-2xl mx-auto space-y-6">
        <header className="flex flex-col md:flex-row md:items-center justify-between bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 transition-colors">
          <div className="mb-4 md:mb-0">
            <h1 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
              <span className="text-google-blue">{t.appTitle}</span>
            </h1>
            <p className="text-gray-500 dark:text-gray-400 text-xs flex items-center gap-1">
                {t.subTitle}
                {isApiReady ? (
                    <span className="text-green-500 flex items-center" title="API Ready"><svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" /></svg></span>
                ) : (
                    <span className="text-red-500 flex items-center cursor-pointer hover:underline" onClick={() => setIsSettingsOpen(true)} title="API Missing">
                        <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                        <span className="ml-1">{t.keyMissing}</span>
                    </span>
                )}
            </p>
          </div>
          <div className="flex flex-wrap items-center gap-3">
             <input type="file" ref={fileInputRef} accept=".xlsx" className="hidden" onChange={handleExcelUpload} />
             <input type="file" ref={importDbInputRef} accept=".json" className="hidden" onChange={handleImportDB} />
            <div className="flex items-center gap-1 bg-gray-50 dark:bg-gray-700/50 p-1 rounded-lg border border-gray-200 dark:border-gray-600">
                <button type="button" onClick={handleExportDB} className="p-2 text-gray-600 dark:text-gray-300 hover:bg-white dark:hover:bg-gray-600 rounded-md transition-all shadow-sm" title={t.exportDb}>
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
                </button>
                <button type="button" onClick={() => importDbInputRef.current?.click()} className="p-2 text-gray-600 dark:text-gray-300 hover:bg-white dark:hover:bg-gray-600 rounded-md transition-all shadow-sm" title={t.importDb}>
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                </button>
                <div className="w-px h-5 bg-gray-300 dark:bg-gray-500 mx-1"></div>
                <button type="button" onClick={handleClearDB} className={`p-2 rounded-md transition-all shadow-sm ${dbDeleteConfirming ? 'bg-red-100 text-red-600 dark:bg-red-900/40 dark:text-red-400' : 'text-gray-600 dark:text-gray-300 hover:bg-white dark:hover:bg-gray-600'}`} title={dbDeleteConfirming ? t.confirmClear : t.clearDb}>
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                </button>
                <div className="w-px h-5 bg-gray-300 dark:bg-gray-500 mx-1"></div>
                <button type="button" onClick={() => setIsSettingsOpen(true)} className={`p-2 rounded-md transition-all shadow-sm ${!isApiReady ? 'text-red-500 bg-red-50 dark:bg-red-900/20 animate-pulse' : 'text-gray-600 dark:text-gray-300 hover:bg-white dark:hover:bg-gray-600'}`} title={t.settingsTitle}>
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                </button>
                <button type="button" onClick={() => setIsHelpOpen(true)} className="p-2 text-gray-600 dark:text-gray-300 hover:bg-white dark:hover:bg-gray-600 rounded-md transition-all shadow-sm" title={t.helpTitle}>
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                </button>
            </div>
          </div>
        </header>

        <div className="space-y-4">
            {compilationInfo && (
              <div className="bg-green-50 dark:bg-green-900/30 border border-green-200 dark:border-green-800 text-green-700 dark:text-green-300 p-4 rounded-lg flex items-center gap-3 animate-fade-in-down">
                 <svg className="w-5 h-5 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                 <div>
                    <span className="font-bold">{t.msgDailyInfo}</span>
                    <span className="ml-2 text-sm opacity-80">{compilationInfo}</span>
                 </div>
              </div>
            )}

            {calcStatus === CalculationStatus.ERROR && errorMsg && (
              <div className="bg-red-50 dark:bg-red-900/30 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-300 p-4 rounded-lg flex items-center gap-3 animate-fade-in">
                 <svg className="w-5 h-5 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" /></svg>
                 <span>{errorMsg}</span>
              </div>
            )}

            <div className="flex flex-col md:flex-row justify-between items-center gap-4 py-2">

                {/* Main Action Group (Left) */}
                <div className="flex flex-wrap items-center gap-2 w-full md:w-auto">
                    {/* Client DB Button - Prominent */}
                    <button type="button" onClick={() => setIsClientDbOpen(true)} className="px-4 py-2 bg-orange-500 hover:bg-orange-600 text-white rounded-lg font-bold text-sm transition-colors flex items-center gap-2 shadow-md transform active:scale-95">
                       <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
                       <span>{t.clientDb}</span>
                    </button>

                    <button type="button" onClick={handleReloadPlan} className="px-3 py-2 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-teal-600 dark:text-teal-400 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 font-medium text-sm transition-colors flex items-center gap-2 shadow-sm">
                       <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                       <span className="hidden md:inline">{t.importPlan}</span>
                    </button>

                    <button type="button" onClick={() => fileInputRef.current?.click()} className="px-3 py-2 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-200 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 font-medium text-sm transition-colors flex items-center gap-2 shadow-sm">
                      <svg className="w-5 h-5 text-green-600 dark:text-green-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                      <span className="hidden md:inline">{t.importExcel}</span>
                    </button>

                    <button type="button" onClick={() => setIsSavedRoutesOpen(true)} className="px-3 py-2 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-200 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 font-medium text-sm transition-colors flex items-center gap-2 shadow-sm" title={t.savedRoutes}>
                        <svg className="w-5 h-5 text-google-blue dark:text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 19a2 2 0 01-2-2V7a2 2 0 012-2h4l2 2h4a2 2 0 012 2v1M5 19h14a2 2 0 002-2v-5a2 2 0 00-2-2H9a2 2 0 00-2 2v5a2 2 0 01-2 2z" /></svg>
                        <span className="hidden md:inline">{t.savedRoutes}</span>
                    </button>

                    <button type="button" onClick={handleAddVisit} className="px-3 py-2 bg-white dark:bg-gray-800 hover:bg-gray-50 dark:hover:bg-gray-700 text-gray-700 dark:text-gray-200 border border-gray-300 dark:border-gray-600 rounded-lg font-medium text-sm transition-colors shadow-sm flex items-center gap-2">
                      <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                      <span>{t.newVisit}</span>
                    </button>

                    {selectedIds.size > 0 && (
                        <button type="button" onClick={handleDeleteClick} className={`px-3 py-2 border rounded-lg font-medium text-sm transition-colors shadow-sm ${deleteConfirming ? 'bg-red-600 text-white border-red-700 hover:bg-red-700' : 'bg-white dark:bg-gray-800 text-red-600 dark:text-red-400 border-gray-300 dark:border-gray-600 hover:bg-red-50 dark:hover:bg-red-900/20'}`}>
                            {deleteConfirming ? t.confirm : `${t.delete} (${selectedIds.size})`}
                        </button>
                    )}
                </div>

                {/* Right Group: Optimization Actions */}
                <div className="flex items-center gap-2 w-full md:w-auto justify-end">
                    <button type="button" onClick={handleValidateAll} disabled={calcStatus === CalculationStatus.ROUTING || calcStatus === CalculationStatus.VALIDATING} className={`px-3 py-2 text-white rounded-lg font-medium text-sm transition-colors shadow-sm flex items-center gap-2 ${calcStatus === CalculationStatus.ROUTING || calcStatus === CalculationStatus.VALIDATING ? 'bg-gray-400 cursor-not-allowed' : 'bg-gray-600 hover:bg-gray-700'}`}>
                         <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                        <span className="hidden md:inline">{t.validate}</span>
                    </button>
                    <button type="button" onClick={() => setIsMapOpen(!isMapOpen)} disabled={!canVisualize} className={`px-3 py-2 text-white rounded-lg font-medium text-sm transition-colors shadow-sm flex items-center gap-2 ${!canVisualize ? 'bg-gray-400 cursor-not-allowed' : 'bg-teal-600 hover:bg-teal-700'}`}>
                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 20l-5.447-2.724A1 1 0 013 16.382V5.618a1 1 0 011.447-.894L9 7m0 13l6-3m-6 3V7m6 10l4.553 2.276A1 1 0 0021 18.382V7.618a1 1 0 00-.553-.894L15 4m0 13V4m0 0L9 7" /></svg>
                        <span className="hidden md:inline">{isMapOpen ? t.hideMap : t.visualize}</span>
                    </button>
                    <button type="button" onClick={handleOptimizeRoute} disabled={calcStatus === CalculationStatus.ROUTING || calcStatus === CalculationStatus.VALIDATING || shouldDisableActions} className={`px-3 py-2 text-white rounded-lg font-medium text-sm transition-colors shadow-sm flex items-center gap-2 ${calcStatus === CalculationStatus.ROUTING || calcStatus === CalculationStatus.VALIDATING || shouldDisableActions ? 'bg-gray-400 cursor-not-allowed' : 'bg-green-600 hover:bg-green-700'}`}>
                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                        <span className="hidden md:inline">{t.optimal}</span>
                    </button>
                    <button type="button" onClick={() => runCalculation(undefined, true)} disabled={calcStatus === CalculationStatus.ROUTING || calcStatus === CalculationStatus.VALIDATING || shouldDisableActions} className={`px-4 py-2 text-white rounded-lg font-medium text-sm transition-colors shadow-sm flex items-center gap-2 ${calcStatus === CalculationStatus.ROUTING || calcStatus === CalculationStatus.VALIDATING || shouldDisableActions ? 'bg-gray-400 cursor-not-allowed' : 'bg-google-blue hover:bg-blue-700'}`}>
                      {calcStatus === CalculationStatus.ROUTING ? (
                         <svg className="animate-spin w-5 h-5" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                      ) : (
                         <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                      )}
                      <span>{t.calculate}</span>
                    </button>
                </div>
            </div>

            <VisitList 
              visits={visits} startTrip={startTrip} returnTrip={returnTrip} selectedIds={selectedIds} onEdit={handleEditVisit} onReorder={handleReorder} onToggleSkip={handleToggleSkip} onDelete={handleDeleteRow}
              onToggleSelect={(id) => { const newSet = new Set(selectedIds); if (newSet.has(id)) newSet.delete(id); else newSet.add(id); setSelectedIds(newSet); }}
              onToggleAll={(checked) => { if (checked) setSelectedIds(new Set(visits.map(v => v.id))); else setSelectedIds(new Set()); }}
              lang={settings.language} departureTime={settings.departureTime}
            />

            {(calcStatus === CalculationStatus.VALIDATING || calcStatus === CalculationStatus.ROUTING) && (
              <div className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-blue-100 dark:border-gray-700 animate-fade-in-down mb-4">
                <div className="flex justify-between mb-2">
                   <span className="text-sm font-semibold text-google-blue">{progress.message}</span>
                   <span className="text-xs text-gray-500 dark:text-gray-400">{Math.round(getProgressWidth())}%</span>
                </div>
                <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2">
                  <div className="bg-google-blue h-2 rounded-full transition-all duration-300 ease-out" style={{ width: `${getProgressWidth()}%` }}></div>
                </div>
              </div>
            )}
            <MapSection isOpen={isMapOpen} onClose={() => setIsMapOpen(false)} startTrip={startTrip} visits={visits} lang={settings.language} />
        </div>
      </div>

      <VisitModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={saveItem} initialData={editingItem} lang={settings.language} mode={editMode} />
      <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} settings={settings} onSave={saveSettings} />
      <SavedRoutesModal isOpen={isSavedRoutesOpen} onClose={() => setIsSavedRoutesOpen(false)} currentVisits={visits} currentStart={startTrip} currentReturn={returnTrip} onLoadRoute={handleLoadSavedRoute} lang={settings.language} />
      <ClientDbModal 
          isOpen={isClientDbOpen} 
          onClose={() => setIsClientDbOpen(false)} 
          clients={clients} 
          onAddClient={handleAddClient} 
          onEditClient={handleEditClient} 
          onDeleteClient={handleDeleteClient}
          onDeleteClients={handleBulkDeleteClients}
          onValidateClients={handleBulkValidateClients}
          onAddToRoute={handleAddClientsToRoute} 
          onImportExcel={handleImportClientsExcel} 
          lang={settings.language} 
      />
      <HelpModal isOpen={isHelpOpen} onClose={() => setIsHelpOpen(false)} lang={settings.language} onLoadSampleData={handleLoadSampleData} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Client } from '../types';
import { translations, Language } from '../services/translations';

interface ClientDbModalProps {
  isOpen: boolean;
  onClose: () => void;
  clients: Client[];
  onAddClient: (data: Omit<Client, 'id'>) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (id: string) => void;
  onDeleteClients: (ids: Set<string>) => void;
  onValidateClients: (ids: Set<string>) => void;
  onAddToRoute: (selectedClients: Client[]) => void;
  onImportExcel: (file: File) => Promise<void>;
  lang: Language;
}

export const ClientDbModal: React.FC<ClientDbModalProps> = ({ 
  isOpen, onClose, clients, onAddClient, onEditClient, onDeleteClient, onDeleteClients, onValidateClients, onAddToRoute, onImportExcel, lang 
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [bulkDeleteConfirm, setBulkDeleteConfirm] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const t = translations[lang];

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    if (isOpen) window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [isOpen, onClose]);

  // Reset bulk delete state when selection changes
  useEffect(() => {
      setBulkDeleteConfirm(false);
  }, [selectedIds]);

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.surname.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.address.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleToggleSelect = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedIds(newSet);
  };

  const handleToggleAll = (checked: boolean) => {
    if (checked) setSelectedIds(new Set(filteredClients.map(c => c.id)));
    else setSelectedIds(new Set());
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (deleteConfirmId === id) {
        onDeleteClient(id);
        setDeleteConfirmId(null);
    } else {
        setDeleteConfirmId(id);
        setTimeout(() => setDeleteConfirmId(null), 3000);
    }
  };

  const handleBulkDelete = () => {
      if (bulkDeleteConfirm) {
          onDeleteClients(selectedIds);
          setSelectedIds(new Set());
          setBulkDeleteConfirm(false);
      } else {
          setBulkDeleteConfirm(true);
          setTimeout(() => setBulkDeleteConfirm(false), 4000);
      }
  };

  const handleBulkValidate = () => {
      onValidateClients(selectedIds);
  };

  const handleExcelChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          await onImportExcel(file);
          if (fileInputRef.current) fileInputRef.current.value = '';
      }
  };

  // Safe default for new client
  const handleAddNew = () => {
      onAddClient({
          name: '', 
          surname: '', 
          address: '', 
          defaultDuration: 30,
          visitRepetition: { type: 'WEEKLY', daysOfWeek: [] }
      });
  };

  // Helper to format Repetition
  const formatRepetition = (c: Client) => {
      const rep = c.visitRepetition;
      if (!rep) return '—';
      if (rep.type === 'WEEKLY') {
          if (!rep.daysOfWeek || rep.daysOfWeek.length === 0) return t.optWeekly;
          const daysShort = rep.daysOfWeek.sort().map(d => t.days[d]).join(', ');
          return `${t.optWeekly}: ${daysShort}`;
      }
      if (rep.type === 'DATE') {
          return `${t.optDate}: ${rep.specificDate || '?'}`;
      }
      if (rep.type === 'INTERVAL') {
          return `${t.optInterval}: ${rep.intervalDays || '?'} days`;
      }
      return '—';
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[110] p-4">
      {/* Increased max-width to 7xl for wider view */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-[90vw] md:max-w-7xl h-[85vh] flex flex-col animate-fade-in-up transition-colors">

        {/* Header */}
        <div className="p-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center bg-white dark:bg-gray-800 rounded-t-lg">
           <h3 className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
             <svg className="w-6 h-6 text-orange-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
             {t.dbTitle}
           </h3>
           <button onClick={onClose} className="text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 p-2">
             <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
           </button>
        </div>

        {/* Toolbar */}
        <div className="p-4 border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 space-y-3">

            {/* Buttons Row (Top) */}
            <div className="flex flex-wrap gap-2 items-center">
                <button onClick={handleAddNew} className="px-3 py-2 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-200 hover:bg-gray-50 dark:hover:bg-gray-700 rounded-lg flex items-center gap-2 text-sm font-medium shadow-sm whitespace-nowrap">
                   <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                   {t.dbAddManual}
                </button>

                <input type="file" ref={fileInputRef} accept=".xlsx" className="hidden" onChange={handleExcelChange} />
                <button onClick={() => fileInputRef.current?.click()} className="px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg text-gray-700 dark:text-gray-200 hover:bg-gray-50 dark:hover:bg-gray-700 flex items-center gap-2 text-sm font-medium whitespace-nowrap">
                   <svg className="w-5 h-5 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                   {t.importExcel}
                </button>

                {selectedIds.size > 0 && (
                    <>
                        <button onClick={handleBulkValidate} className="px-3 py-2 bg-gray-600 hover:bg-gray-700 text-white rounded-lg flex items-center gap-2 text-sm font-medium shadow-sm whitespace-nowrap">
                            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                            {t.validate} ({selectedIds.size})
                        </button>
                        <button onClick={handleBulkDelete} className={`px-3 py-2 border rounded-lg flex items-center gap-2 text-sm font-medium shadow-sm whitespace-nowrap ${bulkDeleteConfirm ? 'bg-red-600 text-white border-red-700' : 'bg-white dark:bg-gray-700 text-red-600 dark:text-red-400 border-gray-300 dark:border-gray-600'}`}>
                            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                            {bulkDeleteConfirm ? t.confirm : `${t.delete} (${selectedIds.size})`}
                        </button>
                    </>
                )}
            </div>

            {/* Search Row (Bottom) */}
            <div className="relative w-full">
                <input 
                   type="text" 
                   placeholder={t.search}
                   className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-google-blue outline-none"
                   value={searchTerm}
                   onChange={e => setSearchTerm(e.target.value)}
                />
                <svg className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
        </div>

        {/* Table */}
        <div className="flex-grow overflow-y-auto bg-gray-50 dark:bg-gray-900/50">
            <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                <thead className="bg-gray-100 dark:bg-gray-800 sticky top-0 z-10 shadow-sm">
                    <tr>
                        <th className="px-4 py-3 w-8">
                             <input type="checkbox" onChange={e => handleToggleAll(e.target.checked)} className="rounded text-google-blue focus:ring-google-blue cursor-pointer" />
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colName}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colSurname}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider w-1/4">{t.colAddress}</th>
                        <th className="px-4 py-3 text-center text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colValid}</th>
                        <th className="px-4 py-3 text-center text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider text-indigo-600 dark:text-indigo-400">{t.colPrefTime}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colRepetition}</th>
                        <th className="px-4 py-3 text-right text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colDurat}</th>
                        <th className="px-4 py-3 text-right text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colActions}</th>
                    </tr>
                </thead>
                <tbody className="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
                    {filteredClients.length === 0 ? (
                        <tr><td colSpan={9} className="text-center py-10 text-gray-500 dark:text-gray-400 italic">{t.dbNoClients}</td></tr>
                    ) : filteredClients.map(client => (
                        <tr 
                          key={client.id} 
                          onDoubleClick={() => onEditClient(client)}
                          className="hover:bg-blue-50 dark:hover:bg-blue-900/10 transition-colors cursor-pointer"
                        >
                            <td className="px-4 py-1 text-center" onClick={e => e.stopPropagation()}>
                                <input 
                                  type="checkbox" 
                                  checked={selectedIds.has(client.id)}
                                  onChange={() => handleToggleSelect(client.id)}
                                  className="rounded text-google-blue focus:ring-google-blue cursor-pointer"
                                />
                            </td>
                            <td className="px-4 py-1 text-sm text-gray-900 dark:text-gray-100 font-medium">{client.name}</td>
                            <td className="px-4 py-1 text-sm text-gray-900 dark:text-gray-100">{client.surname}</td>
                            <td className="px-4 py-1 text-sm text-gray-500 dark:text-gray-400 truncate max-w-xs" title={client.address}>{client.address}</td>
                            <td className="px-4 py-1 text-center">
                                {client.isAddressValid === true && <svg className="w-5 h-5 text-green-500 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>}
                                {client.isAddressValid === false && <svg className="w-5 h-5 text-red-500 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>}
                            </td>
                            <td className="px-4 py-1 text-center text-sm text-indigo-600 dark:text-indigo-400 font-mono">
                                {client.visitStartAt || '—'}
                            </td>
                            <td className="px-4 py-1 text-sm text-gray-600 dark:text-gray-300">
                                {formatRepetition(client)}
                            </td>
                            <td className="px-4 py-1 text-right text-sm text-gray-900 dark:text-gray-100 font-mono">{client.defaultDuration} m</td>
                            <td className="px-4 py-1 text-right flex justify-end gap-2" onClick={e => e.stopPropagation()}>
                                <button onClick={() => onEditClient(client)} className="text-blue-600 hover:bg-blue-100 p-1.5 rounded-full"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
                                <button onClick={(e) => handleDeleteClick(e, client.id)} className={`p-1.5 rounded-full ${deleteConfirmId === client.id ? 'bg-red-600 text-white' : 'text-red-600 hover:bg-red-100'}`}>
                                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                                </button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>

        {/* Footer Actions */}
        <div className="p-4 border-t border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 rounded-b-lg flex justify-between items-center">
            <div className="text-sm text-gray-500 dark:text-gray-400">
                {selectedIds.size} {t.dbSelected}
            </div>
            <div className="flex gap-2">
                <button onClick={onClose} className="px-4 py-2 text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg">{t.close}</button>
                <button 
                  onClick={() => {
                      const selected = clients.filter(c => selectedIds.has(c.id));
                      onAddToRoute(selected);
                  }}
                  disabled={selectedIds.size === 0}
                  className={`px-6 py-2 rounded-lg font-bold shadow-md transition-colors ${selectedIds.size > 0 ? 'bg-green-600 hover:bg-green-700 text-white' : 'bg-gray-300 dark:bg-gray-700 text-gray-500 cursor-not-allowed'}`}
                >
                    {t.addToRoute}
                </button>
            </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Visit, Client, RepetitionType } from '../types';
import { checkAddress } from '../services/googleMapsService';
import { translations, Language } from '../services/translations';

interface VisitModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (data: any) => void;
  initialData?: Visit | Client | null;
  lang: Language;
  mode?: 'visit' | 'client';
}

export const VisitModal: React.FC<VisitModalProps> = ({ isOpen, onClose, onSave, initialData, lang, mode = 'visit' }) => {
  const t = translations[lang];

  const [formData, setFormData] = useState<any>({
    name: '',
    surname: '',
    address: '',
    order: 0,
    visitDuration: 0,
    isAddressValid: false,
    // Client specific
    visitStartAt: '',
    visitRepetition: { type: 'WEEKLY', daysOfWeek: [], specificDate: '', intervalStart: '', intervalDays: 0 }
  });

  const [validationStatus, setValidationStatus] = useState<{isValid?: boolean, msg?: string}>({});
  const [isValidating, setIsValidating] = useState(false);

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
        if (e.key === 'Escape') onClose();
    };

    if (isOpen) {
      window.addEventListener('keydown', handleEsc);
      if (initialData) {
        // Handle both Client (defaultDuration) and Visit (visitDuration)
        const duration = 'visitDuration' in initialData ? initialData.visitDuration : (initialData as any).defaultDuration;
        const isClient = mode === 'client';
        const clientData = isClient ? (initialData as Client) : null;

        setFormData({
            name: initialData.name,
            surname: initialData.surname,
            address: initialData.address,
            order: 'order' in initialData ? initialData.order : 0,
            visitDuration: duration || 0,
            isAddressValid: initialData.isAddressValid || false,
            // Client specific fields
            visitStartAt: clientData?.visitStartAt || '',
            visitRepetition: clientData?.visitRepetition || { type: 'WEEKLY', daysOfWeek: [], specificDate: '', intervalStart: '', intervalDays: 3 }
        });

        if (initialData.isAddressValid) {
            setValidationStatus({ isValid: true, msg: t.msgValidationComplete });
        } else {
            setValidationStatus({});
        }
      } else {
        setFormData({ 
            name: '', surname: '', address: '', order: 0, visitDuration: 0, isAddressValid: false,
            visitStartAt: '',
            visitRepetition: { type: 'WEEKLY', daysOfWeek: [], specificDate: '', intervalStart: new Date().toISOString().slice(0,10), intervalDays: 3 }
        });
        setValidationStatus({});
      }
    }
    return () => window.removeEventListener('keydown', handleEsc);
  }, [isOpen, initialData, onClose, t, mode]);

  if (!isOpen) return null;

  const handleBlur = async () => {
      if (!formData.address) return;
      setIsValidating(true);
      const result = await checkAddress(formData.address);
      setIsValidating(false);
      if (result.isValid) {
          setValidationStatus({ isValid: true, msg: result.formattedAddress });
          setFormData((prev: any) => ({ ...prev, isAddressValid: true }));
      } else {
          setValidationStatus({ isValid: false, msg: result.error });
          setFormData((prev: any) => ({ ...prev, isAddressValid: false }));
      }
  };

  const handleRepetitionChange = (field: string, value: any) => {
      setFormData((prev: any) => ({
          ...prev,
          visitRepetition: { ...prev.visitRepetition, [field]: value }
      }));
  };

  const toggleDay = (dayIndex: number) => {
      const currentDays = formData.visitRepetition.daysOfWeek || [];
      const newDays = currentDays.includes(dayIndex) 
        ? currentDays.filter((d: number) => d !== dayIndex)
        : [...currentDays, dayIndex];
      handleRepetitionChange('daysOfWeek', newDays);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[120] p-4">
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-lg p-6 animate-fade-in-up transition-colors max-h-[90vh] overflow-y-auto">
        <h3 className="text-xl font-semibold mb-4 text-gray-800 dark:text-white">
          {initialData 
            ? (mode === 'client' ? t.editClient : t.editVisit) 
            : (mode === 'client' ? t.createClient : t.createVisit)
          }
        </h3>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblName}</label>
              <input 
                type="text" required
                className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue focus:border-transparent outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                value={formData.name}
                onChange={e => setFormData({...formData, name: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblSurname}</label>
              <input 
                type="text" required
                className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue focus:border-transparent outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                value={formData.surname}
                onChange={e => setFormData({...formData, surname: e.target.value})}
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblVisitAddr}</label>
            <div className="relative">
                <input 
                type="text" required
                className={`w-full border rounded-md p-2 focus:ring-2 outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white ${validationStatus.isValid === false ? 'border-red-300 focus:ring-red-200' : 'border-gray-300 dark:border-gray-600 focus:ring-google-blue'}`}
                value={formData.address}
                onChange={e => {
                    setFormData({...formData, address: e.target.value, isAddressValid: false});
                    setValidationStatus({});
                }}
                onBlur={handleBlur}
                />
                {isValidating && (
                    <div className="absolute right-2 top-2.5">
                        <div className="animate-spin h-4 w-4 border-2 border-google-blue border-t-transparent rounded-full"></div>
                    </div>
                )}
            </div>
            {validationStatus.isValid !== undefined && (
                <div className={`mt-1 text-xs flex items-center gap-1 ${validationStatus.isValid ? 'text-green-600 dark:text-green-400' : 'text-red-600 dark:text-red-400'}`}>
                    <span>{validationStatus.msg}</span>
                </div>
            )}
          </div>

          <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblDuration}</label>
              <input 
                type="number" min="0"
                className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue focus:border-transparent outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                value={formData.visitDuration}
                onChange={e => setFormData({...formData, visitDuration: parseInt(e.target.value) || 0})}
              />
              <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">{t.lblDurationDesc}</p>
          </div>

          {/* Scheduling Section - Only for Clients */}
          {mode === 'client' && (
              <div className="border-t border-gray-200 dark:border-gray-700 pt-4 mt-4">
                  <h4 className="font-bold text-gray-800 dark:text-white mb-3 flex items-center gap-2">
                      <svg className="w-4 h-4 text-orange-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                      {t.lblScheduleTitle}
                  </h4>

                  <div className="grid grid-cols-2 gap-4 mb-4">
                      <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblVisitStartAt}</label>
                          <input 
                            type="time"
                            className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                            value={formData.visitStartAt}
                            onChange={e => setFormData({...formData, visitStartAt: e.target.value})}
                          />
                      </div>
                      <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblRepetitionType}</label>
                          <select 
                            className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                            value={formData.visitRepetition.type}
                            onChange={e => handleRepetitionChange('type', e.target.value as RepetitionType)}
                          >
                              <option value="WEEKLY">{t.optWeekly}</option>
                              <option value="DATE">{t.optDate}</option>
                              <option value="INTERVAL">{t.optInterval}</option>
                          </select>
                      </div>
                  </div>

                  {/* Conditional Scheduling Inputs */}
                  <div className="bg-gray-50 dark:bg-gray-700/50 p-3 rounded-md border border-gray-100 dark:border-gray-600">
                      {formData.visitRepetition.type === 'WEEKLY' && (
                          <div>
                              <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-2 uppercase">{t.lblDaysOfWeek}</label>
                              <div className="flex flex-wrap gap-2">
                                  {t.days.map((dayName: string, idx: number) => {
                                      const isSelected = formData.visitRepetition.daysOfWeek?.includes(idx);
                                      return (
                                          <button
                                            type="button"
                                            key={idx}
                                            onClick={() => toggleDay(idx)}
                                            className={`w-9 h-9 rounded-full text-xs font-bold flex items-center justify-center transition-colors ${isSelected ? 'bg-google-blue text-white shadow-sm' : 'bg-white dark:bg-gray-600 text-gray-600 dark:text-gray-300 border border-gray-200 dark:border-gray-500 hover:bg-gray-100 dark:hover:bg-gray-500'}`}
                                          >
                                              {dayName}
                                          </button>
                                      );
                                  })}
                              </div>
                          </div>
                      )}

                      {formData.visitRepetition.type === 'DATE' && (
                          <div>
                               <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblSpecificDate}</label>
                               <input 
                                 type="date"
                                 className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                                 value={formData.visitRepetition.specificDate || ''}
                                 onChange={e => handleRepetitionChange('specificDate', e.target.value)}
                               />
                          </div>
                      )}

                      {formData.visitRepetition.type === 'INTERVAL' && (
                          <div className="grid grid-cols-2 gap-4">
                              <div>
                                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblIntervalStart}</label>
                                  <input 
                                    type="date"
                                    className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                                    value={formData.visitRepetition.intervalStart || ''}
                                    onChange={e => handleRepetitionChange('intervalStart', e.target.value)}
                                  />
                              </div>
                              <div>
                                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblIntervalDays}</label>
                                  <input 
                                    type="number" min="1"
                                    className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                                    value={formData.visitRepetition.intervalDays || ''}
                                    onChange={e => handleRepetitionChange('intervalDays', parseInt(e.target.value) || 0)}
                                  />
                              </div>
                          </div>
                      )}
                  </div>
              </div>
          )}

          {mode === 'visit' && (
             <div className="text-xs text-gray-500 dark:text-gray-400 italic mt-2">{t.lblDragHint}</div>
          )}

          <div className="flex justify-end space-x-3 mt-6">
            <button 
              type="button" 
              onClick={onClose}
              className="px-4 py-2 text-gray-700 dark:text-gray-200 bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 rounded-md font-medium transition-colors"
            >
              {t.cancel}
            </button>
            <button 
              type="submit" 
              className="px-4 py-2 text-white bg-google-blue hover:bg-blue-700 rounded-md font-medium transition-colors shadow-sm"
            >
              {t.save}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Client } from '../types';
import { translations, Language } from '../services/translations';

interface ClientDbModalProps {
  isOpen: boolean;
  onClose: () => void;
  clients: Client[];
  onAddClient: (data: Omit<Client, 'id'>) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (id: string) => void;
  onDeleteClients: (ids: Set<string>) => void;
  onValidateClients: (ids: Set<string>) => void;
  onAddToRoute: (selectedClients: Client[]) => void;
  onImportExcel: (file: File) => Promise<void>;
  lang: Language;
}

export const ClientDbModal: React.FC<ClientDbModalProps> = ({ 
  isOpen, onClose, clients, onAddClient, onEditClient, onDeleteClient, onDeleteClients, onValidateClients, onAddToRoute, onImportExcel, lang 
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [bulkDeleteConfirm, setBulkDeleteConfirm] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const t = translations[lang];

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    if (isOpen) window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [isOpen, onClose]);

  // Reset bulk delete state when selection changes
  useEffect(() => {
      setBulkDeleteConfirm(false);
  }, [selectedIds]);

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.surname.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.address.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleToggleSelect = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedIds(newSet);
  };

  const handleToggleAll = (checked: boolean) => {
    if (checked) setSelectedIds(new Set(filteredClients.map(c => c.id)));
    else setSelectedIds(new Set());
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (deleteConfirmId === id) {
        onDeleteClient(id);
        setDeleteConfirmId(null);
    } else {
        setDeleteConfirmId(id);
        setTimeout(() => setDeleteConfirmId(null), 3000);
    }
  };

  const handleBulkDelete = () => {
      if (bulkDeleteConfirm) {
          onDeleteClients(selectedIds);
          setSelectedIds(new Set());
          setBulkDeleteConfirm(false);
      } else {
          setBulkDeleteConfirm(true);
          setTimeout(() => setBulkDeleteConfirm(false), 4000);
      }
  };

  const handleBulkValidate = () => {
      onValidateClients(selectedIds);
  };

  const handleExcelChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          await onImportExcel(file);
          if (fileInputRef.current) fileInputRef.current.value = '';
      }
  };

  // Safe default for new client
  const handleAddNew = () => {
      onAddClient({
          name: '', 
          surname: '', 
          address: '', 
          defaultDuration: 30,
          visitRepetition: { type: 'WEEKLY', daysOfWeek: [] }
      });
  };

  // Helper to format Repetition
  const formatRepetition = (c: Client) => {
      const rep = c.visitRepetition;
      if (!rep) return '—';
      if (rep.type === 'WEEKLY') {
          if (!rep.daysOfWeek || rep.daysOfWeek.length === 0) return t.optWeekly;
          const daysShort = rep.daysOfWeek.sort().map(d => t.days[d]).join(', ');
          return `${t.optWeekly}: ${daysShort}`;
      }
      if (rep.type === 'DATE') {
          return `${t.optDate}: ${rep.specificDate || '?'}`;
      }
      if (rep.type === 'INTERVAL') {
          return `${t.optInterval}: ${rep.intervalDays || '?'} days`;
      }
      return '—';
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[110] p-4">
      {/* Increased max-width to 7xl for wider view */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-[90vw] md:max-w-7xl h-[85vh] flex flex-col animate-fade-in-up transition-colors">

        {/* Header */}
        <div className="p-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center bg-white dark:bg-gray-800 rounded-t-lg">
           <h3 className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
             <svg className="w-6 h-6 text-orange-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
             {t.dbTitle}
           </h3>
           <button onClick={onClose} className="text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 p-2">
             <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
           </button>
        </div>

        {/* Toolbar */}
        <div className="p-4 border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 space-y-3">

            {/* Buttons Row (Top) */}
            <div className="flex flex-wrap gap-2 items-center">
                <button onClick={handleAddNew} className="px-3 py-2 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-200 hover:bg-gray-50 dark:hover:bg-gray-700 rounded-lg flex items-center gap-2 text-sm font-medium shadow-sm whitespace-nowrap">
                   <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                   {t.dbAddManual}
                </button>

                <input type="file" ref={fileInputRef} accept=".xlsx" className="hidden" onChange={handleExcelChange} />
                <button onClick={() => fileInputRef.current?.click()} className="px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg text-gray-700 dark:text-gray-200 hover:bg-gray-50 dark:hover:bg-gray-700 flex items-center gap-2 text-sm font-medium whitespace-nowrap">
                   <svg className="w-5 h-5 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                   {t.importExcel}
                </button>

                <button onClick={handleBulkValidate} className="px-3 py-2 bg-gray-600 hover:bg-gray-700 text-white rounded-lg flex items-center gap-2 text-sm font-medium shadow-sm whitespace-nowrap">
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                    {selectedIds.size > 0 ? `${t.validate} (${selectedIds.size})` : `${t.validate} (All)`}
                </button>

                {selectedIds.size > 0 && (
                    <button onClick={handleBulkDelete} className={`px-3 py-2 border rounded-lg flex items-center gap-2 text-sm font-medium shadow-sm whitespace-nowrap ${bulkDeleteConfirm ? 'bg-red-600 text-white border-red-700' : 'bg-white dark:bg-gray-700 text-red-600 dark:text-red-400 border-gray-300 dark:border-gray-600'}`}>
                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                        {bulkDeleteConfirm ? t.confirm : `${t.delete} (${selectedIds.size})`}
                    </button>
                )}
            </div>

            {/* Search Row (Bottom) */}
            <div className="relative w-full">
                <input 
                   type="text" 
                   placeholder={t.search}
                   className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-google-blue outline-none"
                   value={searchTerm}
                   onChange={e => setSearchTerm(e.target.value)}
                />
                <svg className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
        </div>

        {/* Table */}
        <div className="flex-grow overflow-y-auto bg-gray-50 dark:bg-gray-900/50">
            <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                <thead className="bg-gray-100 dark:bg-gray-800 sticky top-0 z-10 shadow-sm">
                    <tr>
                        <th className="px-4 py-3 w-8">
                             <input type="checkbox" onChange={e => handleToggleAll(e.target.checked)} className="rounded text-google-blue focus:ring-google-blue cursor-pointer" />
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colName}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colSurname}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider w-1/4">{t.colAddress}</th>
                        <th className="px-4 py-3 text-center text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colValid}</th>
                        <th className="px-4 py-3 text-center text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider text-indigo-600 dark:text-indigo-400">{t.colPrefTime}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colRepetition}</th>
                        <th className="px-4 py-3 text-right text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colDurat}</th>
                        <th className="px-4 py-3 text-right text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colActions}</th>
                    </tr>
                </thead>
                <tbody className="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
                    {filteredClients.length === 0 ? (
                        <tr><td colSpan={9} className="text-center py-10 text-gray-500 dark:text-gray-400 italic">{t.dbNoClients}</td></tr>
                    ) : filteredClients.map(client => (
                        <tr 
                          key={client.id} 
                          onDoubleClick={() => onEditClient(client)}
                          className="hover:bg-blue-50 dark:hover:bg-blue-900/10 transition-colors cursor-pointer"
                        >
                            <td className="px-4 py-1 text-center" onClick={e => e.stopPropagation()}>
                                <input 
                                  type="checkbox" 
                                  checked={selectedIds.has(client.id)}
                                  onChange={() => handleToggleSelect(client.id)}
                                  className="rounded text-google-blue focus:ring-google-blue cursor-pointer"
                                />
                            </td>
                            <td className="px-4 py-1 text-sm text-gray-900 dark:text-gray-100 font-medium">{client.name}</td>
                            <td className="px-4 py-1 text-sm text-gray-900 dark:text-gray-100">{client.surname}</td>
                            <td className="px-4 py-1 text-sm text-gray-500 dark:text-gray-400 truncate max-w-xs" title={client.address}>{client.address}</td>
                            <td className="px-4 py-1 text-center">
                                {client.isAddressValid === true && <svg className="w-5 h-5 text-green-500 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>}
                                {client.isAddressValid === false && <svg className="w-5 h-5 text-red-500 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>}
                            </td>
                            <td className="px-4 py-1 text-center text-sm text-indigo-600 dark:text-indigo-400 font-mono">
                                {client.visitStartAt || '—'}
                            </td>
                            <td className="px-4 py-1 text-sm text-gray-600 dark:text-gray-300">
                                {formatRepetition(client)}
                            </td>
                            <td className="px-4 py-1 text-right text-sm text-gray-900 dark:text-gray-100 font-mono">{client.defaultDuration} m</td>
                            <td className="px-4 py-1 text-right flex justify-end gap-2" onClick={e => e.stopPropagation()}>
