interface SortableRowProps {
  visit: Visit;
  isSelected: boolean;
  onToggleSelect: (id: string) => void;
  onEdit: (visit: Visit) => void;
  onToggleSkip: (id: string) => void;
  onDelete: (id: string) => void;
