import { useState, useEffect, useRef } from 'react';

export const useDraggable = (isOpen: boolean) => {
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const positionRef = useRef({ x: 0, y: 0 }); // To access current position in closure without re-binding

  const nodeRef = useRef<HTMLDivElement>(null);
  const handleRef = useRef<HTMLElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const startPos = useRef({ x: 0, y: 0 });

  // Sync ref with state
  useEffect(() => {
    positionRef.current = position;
  }, [position]);

  // Reset position when modal re-opens
  useEffect(() => {
    if (isOpen) {
      setPosition({ x: 0, y: 0 });
      positionRef.current = { x: 0, y: 0 };
    }
  }, [isOpen]);

  useEffect(() => {
    const handle = handleRef.current;
    if (!handle) return;

    const handleMouseDown = (e: MouseEvent) => {
      // Allow drag only on left click and ensure we aren't clicking a button/input inside the header
      if (e.button !== 0) return;
      if ((e.target as HTMLElement).closest('button, input, select')) return;

      e.preventDefault(); // Prevent text selection

      isDragging.current = true;
      dragStart.current = { x: e.clientX, y: e.clientY };
      startPos.current = { ...positionRef.current }; // Use ref to get latest without dep

      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      document.body.style.userSelect = 'none';
    };

    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging.current) return;
      const dx = e.clientX - dragStart.current.x;
      const dy = e.clientY - dragStart.current.y;

      setPosition({
        x: startPos.current.x + dx,
        y: startPos.current.y + dy
      });
    };

    const handleMouseUp = () => {
      isDragging.current = false;
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      document.body.style.userSelect = '';
    };

    handle.addEventListener('mousedown', handleMouseDown);
    handle.style.cursor = 'move';

    return () => {
      handle.removeEventListener('mousedown', handleMouseDown);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };
  }, []); // Empty dependency array ensures listeners persist

  return { position, nodeRef, handleRef };
};

