  // Internal mutable state to track drag without re-renders
  const currentPosRef = useRef({ x: 0, y: 0 });
  const isDragging = useRef(false);
  const dragStartMouse = useRef({ x: 0, y: 0 });
  const dragStartElem = useRef({ x: 0, y: 0 });

  // Reset position when modal opens
  useEffect(() => {
    if (isOpen) {
      setPosition({ x: 0, y: 0 });
      currentPosRef.current = { x: 0, y: 0 };
      if (nodeRef.current) {
        nodeRef.current.style.transform = `translate(0px, 0px)`;
      }
    }
  }, [isOpen]);

  // Sync state to DOM (for persistence after drag ends)
  useEffect(() => {
    if (nodeRef.current && !isDragging.current) {
      nodeRef.current.style.transform = `translate(${position.x}px, ${position.y}px)`;
    }
  }, [position]);

  useEffect(() => {
    const handle = handleRef.current;
    if (!isOpen || !handle) return;

    const handleMouseDown = (e: MouseEvent) => {
      if (e.button !== 0) return;
      if ((e.target as HTMLElement).closest('button, input, select, textarea')) return;

      e.preventDefault();
      isDragging.current = true;
      dragStartMouse.current = { x: e.clientX, y: e.clientY };
      dragStartElem.current = { ...currentPosRef.current };

      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      document.body.style.userSelect = 'none';
      handle.style.cursor = 'grabbing';
    };

    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging.current || !nodeRef.current) return;

      const dx = e.clientX - dragStartMouse.current.x;
      const dy = e.clientY - dragStartMouse.current.y;

      const newX = dragStartElem.current.x + dx;
      const newY = dragStartElem.current.y + dy;

      // Direct DOM update for performance
      nodeRef.current.style.transform = `translate(${newX}px, ${newY}px)`;
      currentPosRef.current = { x: newX, y: newY };
    };

    const handleMouseUp = () => {
      if (!isDragging.current) return;

      isDragging.current = false;
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      document.body.style.userSelect = '';
      if (handleRef.current) handleRef.current.style.cursor = 'grab';

      // Save final position to state
      setPosition(currentPosRef.current);
    };

    handle.addEventListener('mousedown', handleMouseDown);
    handle.style.cursor = 'grab';

    return () => {
      handle.removeEventListener('mousedown', handleMouseDown);
      handle.style.cursor = '';
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      document.body.style.userSelect = '';
    };
  }, [isOpen]); 

  return { position, nodeRef, handleRef };
};

import React, { useState, useEffect } from 'react';
import { Visit, Client, RepetitionType } from '../types';
import { checkAddress } from '../services/googleMapsService';
import { translations, Language } from '../services/translations';
import { useDraggable } from '../hooks/useDraggable';

interface VisitModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (data: any) => void;
  initialData?: Visit | Client | null;
  lang: Language;
  mode?: 'visit' | 'client';
}

export const VisitModal: React.FC<VisitModalProps> = ({ isOpen, onClose, onSave, initialData, lang, mode = 'visit' }) => {
  const t = translations[lang];
  const { nodeRef, handleRef } = useDraggable(isOpen);

  const [formData, setFormData] = useState<any>({
    name: '',
    surname: '',
    address: '',
    order: 0,
    visitDuration: 0,
    isAddressValid: false,
    // Client specific
    visitStartAt: '',
    visitRepetition: { type: 'WEEKLY', daysOfWeek: [], specificDate: '', intervalStart: '', intervalDays: 0 }
  });

  const [validationStatus, setValidationStatus] = useState<{isValid?: boolean, msg?: string}>({});
  const [isValidating, setIsValidating] = useState(false);

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
        if (e.key === 'Escape') onClose();
    };

    if (isOpen) {
      window.addEventListener('keydown', handleEsc);
      if (initialData) {
        // Handle both Client (defaultDuration) and Visit (visitDuration)
        const duration = 'visitDuration' in initialData ? initialData.visitDuration : (initialData as any).defaultDuration;
        const isClient = mode === 'client';
        const clientData = isClient ? (initialData as Client) : null;

        setFormData({
            name: initialData.name,
            surname: initialData.surname,
            address: initialData.address,
            order: 'order' in initialData ? initialData.order : 0,
            visitDuration: duration || 0,
            isAddressValid: initialData.isAddressValid || false,
            // Client specific fields
            visitStartAt: clientData?.visitStartAt || '',
            visitRepetition: clientData?.visitRepetition || { type: 'WEEKLY', daysOfWeek: [], specificDate: '', intervalStart: '', intervalDays: 3 }
        });

        if (initialData.isAddressValid) {
            setValidationStatus({ isValid: true, msg: t.msgValidationComplete });
        } else {
            setValidationStatus({});
        }
      } else {
        setFormData({ 
            name: '', surname: '', address: '', order: 0, visitDuration: 0, isAddressValid: false,
            visitStartAt: '',
            visitRepetition: { type: 'WEEKLY', daysOfWeek: [], specificDate: '', intervalStart: new Date().toISOString().slice(0,10), intervalDays: 3 }
        });
        setValidationStatus({});
      }
    }
    return () => window.removeEventListener('keydown', handleEsc);
  }, [isOpen, initialData, onClose, t, mode]);

  if (!isOpen) return null;

  const handleBlur = async () => {
      if (!formData.address) return;
      setIsValidating(true);
      const result = await checkAddress(formData.address);
      setIsValidating(false);
      if (result.isValid) {
          setValidationStatus({ isValid: true, msg: result.formattedAddress });
          setFormData((prev: any) => ({ ...prev, isAddressValid: true }));
      } else {
          setValidationStatus({ isValid: false, msg: result.error });
          setFormData((prev: any) => ({ ...prev, isAddressValid: false }));
      }
  };

  const handleRepetitionChange = (field: string, value: any) => {
      setFormData((prev: any) => ({
          ...prev,
          visitRepetition: { ...prev.visitRepetition, [field]: value }
      }));
  };

  const toggleDay = (dayIndex: number) => {
      const currentDays = formData.visitRepetition.daysOfWeek || [];
      const newDays = currentDays.includes(dayIndex) 
        ? currentDays.filter((d: number) => d !== dayIndex)
        : [...currentDays, dayIndex];
      handleRepetitionChange('daysOfWeek', newDays);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Create a copy to modify before saving
    const submissionData = { ...formData };

    // Sanitize Client Repetition Data: Only keep fields relevant to the selected Type
    if (mode === 'client' && submissionData.visitRepetition) {
        const activeType = submissionData.visitRepetition.type;
        const cleanRepetition: any = { type: activeType };

        if (activeType === 'WEEKLY') {
            cleanRepetition.daysOfWeek = submissionData.visitRepetition.daysOfWeek || [];
        } else if (activeType === 'DATE') {
            cleanRepetition.specificDate = submissionData.visitRepetition.specificDate || '';
        } else if (activeType === 'INTERVAL') {
            cleanRepetition.intervalStart = submissionData.visitRepetition.intervalStart || '';
            cleanRepetition.intervalDays = submissionData.visitRepetition.intervalDays || 0;
        }

        submissionData.visitRepetition = cleanRepetition;
    }

    onSave(submissionData);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[120] p-4">
      <div 
        ref={nodeRef}
        className="bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-lg p-6 animate-fade-in-up transition-colors max-h-[90vh] overflow-y-auto"
      >
        <h3 ref={handleRef} className="text-xl font-semibold mb-4 text-gray-800 dark:text-white select-none">
          {initialData 
            ? (mode === 'client' ? t.editClient : t.editVisit) 
            : (mode === 'client' ? t.createClient : t.createVisit)
          }
        </h3>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblName}</label>
              <input 
                type="text" required
                className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue focus:border-transparent outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                value={formData.name}
                onChange={e => setFormData({...formData, name: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblSurname}</label>
              <input 
                type="text" required
                className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue focus:border-transparent outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                value={formData.surname}
                onChange={e => setFormData({...formData, surname: e.target.value})}
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblVisitAddr}</label>
            <div className="relative">
                <input 
                type="text" required
                className={`w-full border rounded-md p-2 focus:ring-2 outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white ${validationStatus.isValid === false ? 'border-red-300 focus:ring-red-200' : 'border-gray-300 dark:border-gray-600 focus:ring-google-blue'}`}
                value={formData.address}
                onChange={e => {
                    setFormData({...formData, address: e.target.value, isAddressValid: false});
                    setValidationStatus({});
                }}
                onBlur={handleBlur}
                />
                {isValidating && (
                    <div className="absolute right-2 top-2.5">
                        <div className="animate-spin h-4 w-4 border-2 border-google-blue border-t-transparent rounded-full"></div>
                    </div>
                )}
            </div>
            {validationStatus.isValid !== undefined && (
                <div className={`mt-1 text-xs flex items-center gap-1 ${validationStatus.isValid ? 'text-green-600 dark:text-green-400' : 'text-red-600 dark:text-red-400'}`}>
                    <span>{validationStatus.msg}</span>
                </div>
            )}
          </div>

          <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblDuration}</label>
              <input 
                type="number" min="0"
                className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue focus:border-transparent outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                value={formData.visitDuration}
                onChange={e => setFormData({...formData, visitDuration: parseInt(e.target.value) || 0})}
              />
              <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">{t.lblDurationDesc}</p>
          </div>

          {/* Scheduling Section - Only for Clients */}
          {mode === 'client' && (
              <div className="border-t border-gray-200 dark:border-gray-700 pt-4 mt-4">
                  <h4 className="font-bold text-gray-800 dark:text-white mb-3 flex items-center gap-2">
                      <svg className="w-4 h-4 text-orange-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                      {t.lblScheduleTitle}
                  </h4>

                  <div className="grid grid-cols-2 gap-4 mb-4">
                      <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblVisitStartAt}</label>
                          <input 
                            type="time"
                            className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                            value={formData.visitStartAt}
                            onChange={e => setFormData({...formData, visitStartAt: e.target.value})}
                          />
                      </div>
                      <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblRepetitionType}</label>
                          <select 
                            className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                            value={formData.visitRepetition.type}
                            onChange={e => handleRepetitionChange('type', e.target.value as RepetitionType)}
                          >
                              <option value="WEEKLY">{t.optWeekly}</option>
                              <option value="DATE">{t.optDate}</option>
                              <option value="INTERVAL">{t.optInterval}</option>
                          </select>
                      </div>
                  </div>

                  {/* Conditional Scheduling Inputs */}
                  <div className="bg-gray-50 dark:bg-gray-700/50 p-3 rounded-md border border-gray-100 dark:border-gray-600">
                      {formData.visitRepetition.type === 'WEEKLY' && (
                          <div>
                              <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-2 uppercase">{t.lblDaysOfWeek}</label>
                              <div className="flex flex-wrap gap-2">
                                  {t.days.map((dayName: string, idx: number) => {
                                      const isSelected = formData.visitRepetition.daysOfWeek?.includes(idx);
                                      return (
                                          <button
                                            type="button"
                                            key={idx}
                                            onClick={() => toggleDay(idx)}
                                            className={`w-9 h-9 rounded-full text-xs font-bold flex items-center justify-center transition-colors ${isSelected ? 'bg-google-blue text-white shadow-sm' : 'bg-white dark:bg-gray-600 text-gray-600 dark:text-gray-300 border border-gray-200 dark:border-gray-500 hover:bg-gray-100 dark:hover:bg-gray-500'}`}
                                          >
                                              {dayName}
                                          </button>
                                      );
                                  })}
                              </div>
                          </div>
                      )}

                      {formData.visitRepetition.type === 'DATE' && (
                          <div>
                               <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblSpecificDate}</label>
                               <input 
                                 type="date"
                                 className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                                 value={formData.visitRepetition.specificDate || ''}
                                 onChange={e => handleRepetitionChange('specificDate', e.target.value)}
                               />
                          </div>
                      )}

                      {formData.visitRepetition.type === 'INTERVAL' && (
                          <div className="grid grid-cols-2 gap-4">
                              <div>
                                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblIntervalStart}</label>
                                  <input 
                                    type="date"
                                    className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                                    value={formData.visitRepetition.intervalStart || ''}
                                    onChange={e => handleRepetitionChange('intervalStart', e.target.value)}
                                  />
                              </div>
                              <div>
                                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblIntervalDays}</label>
                                  <input 
                                    type="number" min="1"
                                    className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                                    value={formData.visitRepetition.intervalDays || ''}
                                    onChange={e => handleRepetitionChange('intervalDays', parseInt(e.target.value) || 0)}
                                  />
                              </div>
                          </div>
                      )}
                  </div>
              </div>
          )}

          {mode === 'visit' && (
             <div className="text-xs text-gray-500 dark:text-gray-400 italic mt-2">{t.lblDragHint}</div>
          )}

          <div className="flex justify-end space-x-3 mt-6">
            <button 
              type="button" 
              onClick={onClose}
              className="px-4 py-2 text-gray-700 dark:text-gray-200 bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 rounded-md font-medium transition-colors"
            >
              {t.cancel}
            </button>
            <button 
              type="submit" 
              className="px-4 py-2 text-white bg-google-blue hover:bg-blue-700 rounded-md font-medium transition-colors shadow-sm"
            >
              {t.save}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppSettings } from '../types';
import { checkAddress } from '../services/googleMapsService';
import { translations, Language } from '../services/translations';
import { useDraggable } from '../hooks/useDraggable';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  settings: AppSettings;
  onSave: (newSettings: AppSettings) => void;
}

export const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, settings, onSave }) => {
  const [formData, setFormData] = useState<AppSettings>(settings);
  const [validationStatus, setValidationStatus] = useState<{isValid?: boolean, msg?: string}>({});
  const [isValidating, setIsValidating] = useState(false);
  const [keyStatus, setKeyStatus] = useState<'valid' | 'invalid' | 'unknown'>('unknown');

  const { nodeRef, handleRef } = useDraggable(isOpen);
  const t = translations[settings.language || 'cs'];

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
        if (e.key === 'Escape') onClose();
    };

    if (isOpen) {
        window.addEventListener('keydown', handleEsc);
        setFormData(settings);
        if (settings.isStartValid) {
            setValidationStatus({ isValid: true, msg: t.msgValidationComplete });
        } else {
            setValidationStatus({});
        }

        if (settings.googleApiKey && settings.googleApiKey.startsWith('AIza')) {
            setKeyStatus('valid');
        } else if (settings.googleApiKey) {
            setKeyStatus('invalid');
        } else {
            setKeyStatus('unknown');
        }
    }

    return () => window.removeEventListener('keydown', handleEsc);
  }, [isOpen, settings, onClose, t]);

  if (!isOpen) return null;

  const handleBlur = async () => {
      if (!formData.startAddress) return;
      setIsValidating(true);
      const result = await checkAddress(formData.startAddress);
      setIsValidating(false);

      if (result.isValid) {
          setValidationStatus({ isValid: true, msg: result.formattedAddress });
          setFormData(prev => ({ ...prev, isStartValid: true }));
      } else {
          setValidationStatus({ isValid: false, msg: result.error });
          setFormData(prev => ({ ...prev, isStartValid: false }));
      }
  };

  const handleKeyChange = (val: string) => {
      setFormData(prev => ({ ...prev, googleApiKey: val }));
      if (val.trim().startsWith('AIza')) {
          setKeyStatus('valid');
      } else if (val.trim().length > 0) {
          setKeyStatus('invalid');
      } else {
          setKeyStatus('unknown');
      }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[130]">
      <div 
        ref={nodeRef}
        className="bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-md p-6 animate-fade-in-up transition-colors max-h-[90vh] overflow-y-auto"
      >
        <h3 ref={handleRef} className="text-xl font-semibold mb-4 text-gray-800 dark:text-white select-none">{t.settingsTitle}</h3>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div className="bg-blue-50 dark:bg-blue-900/20 p-3 rounded-md border border-blue-100 dark:border-blue-800">
             <label className="block text-sm font-bold text-gray-700 dark:text-gray-200 mb-1">
                 {t.lblApiKey} <span className="text-red-500">*</span>
             </label>
             <div className="relative">
                 <input 
                   type="text" 
                   required
                   className={`w-full border rounded-md p-2 focus:ring-2 outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white font-mono text-sm
                      ${keyStatus === 'valid' ? 'border-green-400 focus:ring-green-300' : ''}
                      ${keyStatus === 'invalid' ? 'border-red-400 focus:ring-red-300' : 'border-gray-300 dark:border-gray-600 focus:ring-google-blue'}
                   `}
                   value={formData.googleApiKey || ''}
                   onChange={e => handleKeyChange(e.target.value)}
                   placeholder="AIzaSy..."
                 />
                 <div className="absolute right-2 top-2.5">
                    {keyStatus === 'valid' && (
                        <svg className="w-5 h-5 text-green-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                    )}
                    {keyStatus === 'invalid' && (
                        <svg className="w-5 h-5 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                    )}
                 </div>
             </div>
             <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">{t.lblApiKeyDesc}</p>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblAddress}</label>
            <div className="relative">
                <textarea 
                rows={3}
                required
                className={`w-full border rounded-md p-2 focus:ring-2 outline-none resize-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white
                    ${validationStatus.isValid === false ? 'border-red-300 focus:ring-red-200' : 'border-gray-300 dark:border-gray-600 focus:ring-google-blue'}`}
                value={formData.startAddress}
                onChange={e => {
                    setFormData({...formData, startAddress: e.target.value, isStartValid: false});
                    setValidationStatus({}); 
                }}
                onBlur={handleBlur}
                placeholder="e.g. J. Palacha 324, Pardubice"
                />
                {isValidating && (
                    <div className="absolute right-2 top-2">
                        <div className="animate-spin h-4 w-4 border-2 border-google-blue border-t-transparent rounded-full"></div>
                    </div>
                )}
            </div>
            {validationStatus.isValid !== undefined && (
                <div className={`mt-1 text-xs flex items-center gap-1 ${validationStatus.isValid ? 'text-green-600 dark:text-green-400' : 'text-red-600 dark:text-red-400'}`}>
                    <span>{validationStatus.msg}</span>
                </div>
            )}
          </div>

          <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblOdometer}</label>
                <input 
                  type="number" 
                  className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue focus:border-transparent outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                  value={formData.currentOdometer}
                  onChange={e => setFormData({...formData, currentOdometer: parseInt(e.target.value) || 0})}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblDeparture}</label>
                <input 
                  type="time" 
                  step="1"
                  className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue focus:border-transparent outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                  value={formData.departureTime}
                  onChange={e => setFormData({...formData, departureTime: e.target.value})}
                />
              </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblCache}</label>
                <input 
                  type="number" 
                  min="1"
                  className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue focus:border-transparent outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                  value={formData.cacheExpirationDays || 30}
                  onChange={e => setFormData({...formData, cacheExpirationDays: parseInt(e.target.value) || 30})}
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblLanguage}</label>
                <select 
                    className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue focus:border-transparent outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                    value={formData.language || 'cs'}
                    onChange={e => setFormData({...formData, language: e.target.value as Language})}
                >
                    <option value="cs">Čeština</option>
                    <option value="en">English</option>
                </select>
              </div>
          </div>

          <div className="space-y-3 pt-2">
            <div className="flex items-center space-x-2 bg-gray-50 dark:bg-gray-700 p-3 rounded-md border border-gray-200 dark:border-gray-600">
                <input 
                type="checkbox" 
                id="strictMode"
                checked={formData.isStrictMode}
                onChange={e => setFormData({...formData, isStrictMode: e.target.checked})}
                className="h-4 w-4 text-google-blue focus:ring-google-blue border-gray-300 dark:border-gray-500 rounded cursor-pointer"
                />
                <label htmlFor="strictMode" className="text-sm text-gray-700 dark:text-gray-200 cursor-pointer select-none">
                {t.lblStrictMode}
                </label>
            </div>

            <div className="flex items-center justify-between bg-gray-50 dark:bg-gray-700 p-3 rounded-md border border-gray-200 dark:border-gray-600">
                <span className="text-sm text-gray-700 dark:text-gray-200 select-none">{t.lblDarkMode}</span>
                <button
                    type="button"
                    onClick={() => setFormData({...formData, isDarkMode: !formData.isDarkMode})}
                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-google-blue focus:ring-offset-2 ${formData.isDarkMode ? 'bg-google-blue' : 'bg-gray-200'}`}
                >
                    <span
                        className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${formData.isDarkMode ? 'translate-x-6' : 'translate-x-1'}`}
                    />
                </button>
            </div>
          </div>

          <div className="flex justify-end space-x-3 mt-6">
            <button 
              type="button" 
              onClick={onClose}
              className="px-4 py-2 text-gray-700 dark:text-gray-200 bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 rounded-md font-medium transition-colors"
            >
              {t.cancel}
            </button>
            <button 
              type="submit" 
              className="px-4 py-2 text-white bg-google-blue hover:bg-blue-700 rounded-md font-medium transition-colors shadow-sm"
            >
              {t.saveSettings}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { SavedRoute, Visit, StartTrip, ReturnTrip } from '../types';
import { translations, Language } from '../services/translations';
import { useDraggable } from '../hooks/useDraggable';

interface SavedRoutesModalProps {
  isOpen: boolean;
  onClose: () => void;
  currentVisits: Visit[];
  currentStart: StartTrip | null;
  currentReturn: ReturnTrip | null;
  onLoadRoute: (route: SavedRoute) => void;
  lang: Language;
}

export const SavedRoutesModal: React.FC<SavedRoutesModalProps> = ({ 
  isOpen, onClose, currentVisits, currentStart, currentReturn, onLoadRoute, lang 
}) => {
  const [savedRoutes, setSavedRoutes] = useState<SavedRoute[]>([]);
  const [newRouteName, setNewRouteName] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'save'>('list');
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const t = translations[lang];
  const { nodeRef, handleRef } = useDraggable(isOpen);

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        console.debug("Escape pressed in SavedRoutesModal");
        onClose();
      }
    };

    if (isOpen) {
      window.addEventListener('keydown', handleEsc, true); // Use capture to ensure priority
      loadRoutesFromStorage();
      setViewMode('list');
      setNewRouteName('');
      setDeletingId(null);
    }
    return () => window.removeEventListener('keydown', handleEsc, true);
  }, [isOpen, onClose]);

  const loadRoutesFromStorage = () => {
    try {
      const raw = localStorage.getItem('odocalc_saved_routes');
      if (raw) {
        setSavedRoutes(JSON.parse(raw));
      }
    } catch (e) {
      console.error("Failed to load saved routes", e);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRouteName.trim()) return;

    const newRoute: SavedRoute = {
      id: Math.random().toString(36).substring(2, 9),
      name: newRouteName.trim(),
      createdAt: new Date().toISOString(),
      visits: currentVisits,
      startTrip: currentStart,
      returnTrip: currentReturn
    };

    const updatedRoutes = [...savedRoutes, newRoute];
    localStorage.setItem('odocalc_saved_routes', JSON.stringify(updatedRoutes));
    setSavedRoutes(updatedRoutes);
    setNewRouteName('');
    setViewMode('list');
    console.log(`Route "${newRouteName}" saved successfully.`);
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    e.preventDefault();

    if (deletingId === id) {
      const updatedRoutes = savedRoutes.filter(r => r.id !== id);
      localStorage.setItem('odocalc_saved_routes', JSON.stringify(updatedRoutes));
      setSavedRoutes(updatedRoutes);
      setDeletingId(null);
      console.log(`Route ${id} deleted permanently.`);
    } else {
      setDeletingId(id);
      setTimeout(() => {
        setDeletingId(prev => (prev === id ? null : prev));
      }, 4000);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[110] p-4">
      <div 
        ref={nodeRef}
        className="bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-lg p-6 animate-fade-in-up transition-colors max-h-[80vh] flex flex-col"
      >
        <div ref={handleRef} className="flex justify-between items-center mb-4 border-b border-gray-200 dark:border-gray-700 pb-2 select-none">
            <h3 className="text-xl font-bold text-gray-800 dark:text-white">
                {viewMode === 'list' ? t.savedRoutesTitle : t.saveRouteTitle}
            </h3>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
        </div>

        {viewMode === 'list' && (
          <div className="flex-grow overflow-y-auto min-h-[300px] pr-1">
            <div className="flex justify-between items-center mb-4">
               <p className="text-sm text-gray-500 dark:text-gray-400">
                   {savedRoutes.length === 0 ? t.noSavedRoutes : `${savedRoutes.length} ${t.routesFound}`}
               </p>
               <button 
                  onClick={() => setViewMode('save')}
                  disabled={currentVisits.length === 0}
                  className={`px-3 py-1.5 rounded-md text-sm font-medium flex items-center gap-2 transition-colors ${currentVisits.length === 0 ? 'bg-gray-100 text-gray-400 cursor-not-allowed' : 'bg-green-600 hover:bg-green-700 text-white'}`}
               >
                   <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                   {t.btnSaveCurrent}
               </button>
            </div>

            <div className="space-y-2">
                {savedRoutes.map(route => {
                    const isDeleting = deletingId === route.id;
                    return (
                        <div key={route.id} className={`bg-gray-50 dark:bg-gray-700/50 p-3 rounded-lg border transition-colors flex justify-between items-center group relative ${isDeleting ? 'border-red-500 bg-red-50 dark:bg-red-900/20' : 'border-gray-200 dark:border-gray-700 hover:border-google-blue dark:hover:border-blue-500'}`}>
                            <div onClick={() => { if(!isDeleting) { onLoadRoute(route); onClose(); } }} className={`cursor-pointer flex-grow ${isDeleting ? 'opacity-50 pointer-events-none' : ''}`}>
                                <h4 className={`font-bold transition-colors ${isDeleting ? 'text-red-600' : 'text-gray-800 dark:text-gray-200 group-hover:text-google-blue dark:group-hover:text-blue-400'}`}>
                                    {route.name}
                                </h4>
                                <div className="text-xs text-gray-500 dark:text-gray-400 flex items-center gap-2 mt-1">
                                    <span>{new Date(route.createdAt).toLocaleDateString()}</span>
                                    <span>•</span>
                                    <span>{route.visits.length} {t.stops}</span>
                                </div>
                            </div>
                            <div className="flex items-center gap-2">
                                {!isDeleting && (
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); onLoadRoute(route); onClose(); }}
                                        className="p-2 text-google-blue hover:bg-blue-50 dark:hover:bg-blue-900/30 rounded-full" 
                                        title={t.load}
                                    >
                                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
                                    </button>
                                )}
                                <button 
                                    onClick={(e) => handleDelete(e, route.id)}
                                    className={`p-2 rounded-full transition-all flex items-center justify-center min-w-[36px] min-h-[36px] ${isDeleting ? 'bg-red-600 text-white shadow-md scale-110' : 'text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30'}`}
                                    title={isDeleting ? t.confirm : t.delete}
                                >
                                    {isDeleting ? (
                                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                                        </svg>
                                    ) : (
                                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                        </svg>
                                    )}
                                </button>
                            </div>
                            {isDeleting && (
                                <div className="absolute inset-0 bg-red-600/5 rounded-lg flex items-center justify-center pointer-events-none">
                                    <span className="text-[10px] font-bold text-red-600 dark:text-red-400 uppercase tracking-widest translate-y-6">{t.confirm}</span>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
          </div>
        )}

        {viewMode === 'save' && (
            <form onSubmit={handleSave} className="flex flex-col gap-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblRouteName}</label>
                    <input 
                        type="text" 
                        required
                        autoFocus
                        className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                        value={newRouteName}
                        onChange={e => setNewRouteName(e.target.value)}
                        placeholder="e.g. Pondělí - Hradec"
                    />
                </div>
                <div className="bg-blue-50 dark:bg-blue-900/20 p-3 rounded text-sm text-gray-600 dark:text-gray-300">
                    <p>{t.saveRouteDesc}</p>
                    <ul className="list-disc pl-5 mt-1 text-xs">
                        <li>{currentVisits.length} {t.stops}</li>
                        <li>{t.start}: {currentStart?.address || 'N/A'}</li>
                    </ul>
                </div>
                <div className="flex justify-end gap-2 mt-2">
                    <button 
                        type="button" 
                        onClick={() => setViewMode('list')}
                        className="px-4 py-2 text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-md"
                    >
                        {t.cancel}
                    </button>
                    <button 
                        type="submit"
                        className="px-4 py-2 bg-google-blue hover:bg-blue-700 text-white rounded-md font-medium shadow-sm"
                    >
                        {t.save}
                    </button>
                </div>
            </form>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Client } from '../types';
import { translations, Language } from '../services/translations';
import { useDraggable } from '../hooks/useDraggable';

interface ClientDbModalProps {
  isOpen: boolean;
  onClose: () => void;
  clients: Client[];
  onAddClient: (data: Omit<Client, 'id'>) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (id: string) => void;
  onDeleteClients: (ids: Set<string>) => void;
  onValidateClients: (ids: Set<string>) => void;
  onAddToRoute: (selectedClients: Client[]) => void;
  onImportExcel: (file: File) => Promise<void>;
  lang: Language;
}

export const ClientDbModal: React.FC<ClientDbModalProps> = ({ 
  isOpen, onClose, clients, onAddClient, onEditClient, onDeleteClient, onDeleteClients, onValidateClients, onAddToRoute, onImportExcel, lang 
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [bulkDeleteConfirm, setBulkDeleteConfirm] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const t = translations[lang];
  const { nodeRef, handleRef } = useDraggable(isOpen);

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    if (isOpen) window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [isOpen, onClose]);

  // Reset bulk delete state when selection changes
  useEffect(() => {
      setBulkDeleteConfirm(false);
  }, [selectedIds]);

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.surname.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.address.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleToggleSelect = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedIds(newSet);
  };

  const handleToggleAll = (checked: boolean) => {
    if (checked) setSelectedIds(new Set(filteredClients.map(c => c.id)));
    else setSelectedIds(new Set());
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (deleteConfirmId === id) {
        onDeleteClient(id);
        setDeleteConfirmId(null);
    } else {
        setDeleteConfirmId(id);
        setTimeout(() => setDeleteConfirmId(null), 3000);
    }
  };

  const handleBulkDelete = () => {
      if (bulkDeleteConfirm) {
          onDeleteClients(selectedIds);
          setSelectedIds(new Set());
          setBulkDeleteConfirm(false);
      } else {
          setBulkDeleteConfirm(true);
          setTimeout(() => setBulkDeleteConfirm(false), 4000);
      }
  };

  const handleBulkValidate = () => {
      onValidateClients(selectedIds);
  };

  const handleExcelChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          await onImportExcel(file);
          if (fileInputRef.current) fileInputRef.current.value = '';
      }
  };

  // Safe default for new client
  const handleAddNew = () => {
      onAddClient({
          name: '', 
          surname: '', 
          address: '', 
          defaultDuration: 30,
          visitRepetition: { type: 'WEEKLY', daysOfWeek: [] }
      });
  };

  // Helper to format Repetition
  const formatRepetition = (c: Client) => {
      const rep = c.visitRepetition;
      if (!rep) return '—';
      if (rep.type === 'WEEKLY') {
          if (!rep.daysOfWeek || rep.daysOfWeek.length === 0) return t.optWeekly;
          const daysShort = rep.daysOfWeek.sort().map(d => t.days[d]).join(', ');
          return `${t.optWeekly}: ${daysShort}`;
      }
      if (rep.type === 'DATE') {
          return `${t.optDate}: ${rep.specificDate || '?'}`;
      }
      if (rep.type === 'INTERVAL') {
          return `${t.optInterval}: ${rep.intervalDays || '?'} days`;
      }
      return '—';
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[110] p-4">
      {/* Increased max-width to 7xl for wider view */}
      <div 
        ref={nodeRef}
        className="bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-[90vw] md:max-w-7xl h-[85vh] flex flex-col animate-fade-in-up transition-colors"
      >

        {/* Header */}
        <div ref={handleRef} className="p-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center bg-white dark:bg-gray-800 rounded-t-lg select-none">
           <h3 className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
             <svg className="w-6 h-6 text-orange-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
             {t.dbTitle}
           </h3>
           <button onClick={onClose} className="text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 p-2">
             <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
           </button>
        </div>

        {/* Toolbar */}
        <div className="p-4 border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 space-y-3">

            {/* Buttons Row (Top) */}
            <div className="flex flex-wrap gap-2 items-center">
                <button onClick={handleAddNew} className="px-3 py-2 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-200 hover:bg-gray-50 dark:hover:bg-gray-700 rounded-lg flex items-center gap-2 text-sm font-medium shadow-sm whitespace-nowrap">
                   <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                   {t.dbAddManual}
                </button>

                <input type="file" ref={fileInputRef} accept=".xlsx" className="hidden" onChange={handleExcelChange} />
                <button onClick={() => fileInputRef.current?.click()} className="px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg text-gray-700 dark:text-gray-200 hover:bg-gray-50 dark:hover:bg-gray-700 flex items-center gap-2 text-sm font-medium whitespace-nowrap">
                   <svg className="w-5 h-5 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                   {t.importExcel}
                </button>

                <button onClick={handleBulkValidate} className="px-3 py-2 bg-gray-600 hover:bg-gray-700 text-white rounded-lg flex items-center gap-2 text-sm font-medium shadow-sm whitespace-nowrap">
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                    {selectedIds.size > 0 ? `${t.validate} (${selectedIds.size})` : `${t.validate}`}
                </button>

                {selectedIds.size > 0 && (
                    <button onClick={handleBulkDelete} className={`px-3 py-2 border rounded-lg flex items-center gap-2 text-sm font-medium shadow-sm whitespace-nowrap ${bulkDeleteConfirm ? 'bg-red-600 text-white border-red-700' : 'bg-white dark:bg-gray-700 text-red-600 dark:text-red-400 border-gray-300 dark:border-gray-600'}`}>
                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                        {bulkDeleteConfirm ? t.confirm : `${t.delete} (${selectedIds.size})`}
                    </button>
                )}
            </div>

            {/* Search Row (Bottom) */}
            <div className="relative w-full">
                <input 
                   type="text" 
                   placeholder={t.search}
                   className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-google-blue outline-none"
                   value={searchTerm}
                   onChange={e => setSearchTerm(e.target.value)}
                />
                <svg className="w-5 h-5 text-gray-400 absolute left-3 top-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
        </div>

        {/* Table */}
        <div className="flex-grow overflow-y-auto bg-gray-50 dark:bg-gray-900/50">
            <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                <thead className="bg-gray-100 dark:bg-gray-800 sticky top-0 z-10 shadow-sm">
                    <tr>
                        <th className="px-4 py-3 w-8">
                             <input type="checkbox" onChange={e => handleToggleAll(e.target.checked)} className="rounded text-google-blue focus:ring-google-blue cursor-pointer" />
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colName}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colSurname}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider w-1/4">{t.colAddress}</th>
                        <th className="px-4 py-3 text-center text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t.colValid}</th>
