                 </div>
              </div>
            )}

            {(calcStatus === CalculationStatus.VALIDATING || calcStatus === CalculationStatus.ROUTING) && (
              <div className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-blue-100 dark:border-gray-700 animate-fade-in-down mb-4">
                <div className="flex justify-between mb-2">
                   <span className="text-sm font-semibold text-google-blue">{progress.message}</span>
                   <span className="text-xs text-gray-500 dark:text-gray-400">{Math.round(getProgressWidth())}%</span>
                </div>
                <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2">
                  <div className="bg-google-blue h-2 rounded-full transition-all duration-300 ease-out" style={{ width: `${getProgressWidth()}%` }}></div>
                </div>
              </div>
            )}
            <MapSection isOpen={isMapOpen} onClose={() => setIsMapOpen(false)} startTrip={startTrip} visits={visits} lang={settings.language} />
        </div>
      </div>

      <VisitModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSave={saveItem} initialData={editingItem} lang={settings.language} mode={editMode} />
      <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} settings={settings} onSave={saveSettings} />
      <SavedRoutesModal isOpen={isSavedRoutesOpen} onClose={() => setIsSavedRoutesOpen(false)} currentVisits={visits} currentStart={startTrip} currentReturn={returnTrip} onLoadRoute={handleLoadSavedRoute} lang={settings.language} />
      <ClientDbModal 
          isOpen={isClientDbOpen} 
          onClose={() => setIsClientDbOpen(false)} 
          clients={clients} 
          onAddClient={handleAddClient} 
          onEditClient={handleEditClient} 
          onDeleteClient={handleDeleteClient}
          onDeleteClients={handleBulkDeleteClients}
          onValidateClients={handleBulkValidateClients}
          onAddToRoute={handleAddClientsToRoute} 
          onImportExcel={handleImportClientsExcel} 
          lang={settings.language} 
      />
      <HelpModal isOpen={isHelpOpen} onClose={() => setIsHelpOpen(false)} lang={settings.language} onLoadSampleData={handleLoadSampleData} />
    </div>
  );
};

export default App;

export interface Visit {
  id: string; // Unique ID for React keys and selection tracking
  name: string;
  surname: string;
  address: string;
  order: number;
  visitDuration: number; // Duration of the visit in minutes (service time)
  isSkipped?: boolean; // New field to exclude from calculation
  isAddressValid?: boolean; // New field for instant validation status
  // Calculated fields (optional)
  segmentDistance?: number;
  exactDistanceKm?: number; // Unrounded distance
  segmentDuration?: number; // seconds
  arrivalTime?: string; // Calculated time of arrival (HH:mm:ss)
  totalOdometer?: number;
  // Dynamic compilation fields
  preferredTime?: string; // HH:mm copy from Client for reference
}

export type RepetitionType = 'WEEKLY' | 'DATE' | 'INTERVAL';

export interface VisitRepetition {
  type: RepetitionType;
  daysOfWeek?: number[]; // 0=Sunday, 1=Monday...
  specificDate?: string; // YYYY-MM-DD
  intervalStart?: string; // YYYY-MM-DD
  intervalDays?: number;
}

// Persistent Client (Database entity)
export interface Client {
  id: string;
  name: string;
  surname: string;
  address: string;
  defaultDuration: number;
  email?: string;
  phone?: string;
  notes?: string;
  isAddressValid?: boolean;

  // New Scheduling Fields
  visitStartAt?: string; // HH:mm - Preferred time / Sort order
  visitRepetition?: VisitRepetition;
}

// Persistent Storage for Routes
export interface SavedRoute {
  id: string;
  name: string;
  createdAt: string; // ISO Date string
  visits: Visit[];
  startAddress?: string; // Optional: save start address with route
  startTrip?: StartTrip | null;
  returnTrip?: ReturnTrip | null;
}

// Start trip data (Start of the journey)
export interface StartTrip {
  address: string;
  odometer: number;
}

// Return trip data (End of the journey)
export interface ReturnTrip {
  address: string;
  segmentDistance: number;
  exactDistanceKm?: number; // Unrounded distance
  segmentDuration: number;
  arrivalTime?: string; // Calculated time of arrival back at base
  totalOdometer?: number;
}

export interface AppSettings {
  startAddress: string;
  currentOdometer: number;
  departureTime: string; // HH:mm:ss
  isStrictMode: boolean;
  isStartValid?: boolean; // Track if start address is validated
  isDarkMode: boolean; // Dark mode toggle
  googleApiKey?: string; // User provided API Key (Unencrypted)
  cacheExpirationDays?: number; // Cache expiration in days
  language: 'cs' | 'en'; // Display language
}

export enum CalculationStatus {
  IDLE = 'IDLE',
  VALIDATING = 'VALIDATING',
  ROUTING = 'ROUTING',
  COMPLETE = 'COMPLETE',
  ERROR = 'ERROR'
}

// Payload for Cloud Sync
export interface BackupData {
  clients: Client[];
  settings: AppSettings;
  savedRoutes: SavedRoute[];
  lmod: any; // Cache object
  timestamp: number; // Last modified time
}

import { initializeApp } from "firebase/app";
import { getAuth, GoogleAuthProvider, signInWithPopup, signOut, User } from "firebase/auth";
import { getFirestore, doc, setDoc, getDoc } from "firebase/firestore";
import { BackupData, Client, AppSettings, SavedRoute } from "../types";

const firebaseConfig = {
  apiKey: "***REMOVED***",
  authDomain: "proj-visopt.firebaseapp.com",
  projectId: "proj-visopt",
  storageBucket: "proj-visopt.firebasestorage.app",
  messagingSenderId: "1048476373474",
  appId: "1:1048476373474:web:f629e9f83179f98970e9bb"
};

const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
const db = getFirestore(app);
const provider = new GoogleAuthProvider();

const COLLECTION = "localstorage";

export const FirebaseService = {

  signIn: async () => {
    try {
      await signInWithPopup(auth, provider);
    } catch (error) {
      console.error("Firebase Sign In Error", error);
      throw error;
    }
  },

  signOut: async () => {
    try {
      await signOut(auth);
    } catch (error) {
      console.error("Firebase Sign Out Error", error);
    }
  },

  /**
   * Syncs local data to Firestore (Upload)
   */
  syncUp: async (user: User) => {
    if (!user || !user.email) return;

    try {
      const clients = JSON.parse(localStorage.getItem('odocalc_db_clients') || '[]');
      const settings = JSON.parse(localStorage.getItem('odocalc_settings') || '{}');
      const savedRoutes = JSON.parse(localStorage.getItem('odocalc_saved_routes') || '[]');
      const lmod = JSON.parse(localStorage.getItem('odocalc_lmod') || '{}');

      const payload: BackupData = {
        clients,
        settings,
        savedRoutes,
        lmod,
        timestamp: Date.now()
      };

      await setDoc(doc(db, COLLECTION, user.email), payload);

      // Update local tracking timestamp
      localStorage.setItem('odocalc_last_modified', payload.timestamp.toString());

      console.log(`[Cloud] Synced UP successfully for ${user.email}`);
    } catch (e) {
      console.error("[Cloud] Sync UP failed", e);
    }
  },

  /**
   * Syncs Cloud data to Local (Download)
   * Returns true if data was updated, false otherwise.
   */
  syncDown: async (user: User): Promise<{ updated: boolean, data?: BackupData }> => {
    if (!user || !user.email) return { updated: false };

    try {
      const docRef = doc(db, COLLECTION, user.email);
      const docSnap = await getDoc(docRef);

      if (docSnap.exists()) {
        const cloudData = docSnap.data() as BackupData;
        const localTs = parseInt(localStorage.getItem('odocalc_last_modified') || '0');

        console.log(`[Cloud] Timestamp Check - Local: ${localTs}, Cloud: ${cloudData.timestamp}`);

        // If Cloud is newer than Local, overwrite Local
        if (cloudData.timestamp > localTs) {
          localStorage.setItem('odocalc_db_clients', JSON.stringify(cloudData.clients || []));
          localStorage.setItem('odocalc_settings', JSON.stringify(cloudData.settings || {}));
          localStorage.setItem('odocalc_saved_routes', JSON.stringify(cloudData.savedRoutes || []));
          localStorage.setItem('odocalc_lmod', JSON.stringify(cloudData.lmod || {}));
          localStorage.setItem('odocalc_last_modified', cloudData.timestamp.toString());

          console.log(`[Cloud] Synced DOWN successfully. Local updated.`);
          return { updated: true, data: cloudData };
        }
      }
    } catch (e) {
      console.error("[Cloud] Sync DOWN failed", e);
    }
    return { updated: false };
  }
};

import React, { useState, useEffect } from 'react';
import { SavedRoute, Visit, StartTrip, ReturnTrip } from '../types';
import { translations, Language } from '../services/translations';
import { useDraggable } from '../hooks/useDraggable';

interface SavedRoutesModalProps {
  isOpen: boolean;
  onClose: () => void;
  currentVisits: Visit[];
  currentStart: StartTrip | null;
  currentReturn: ReturnTrip | null;
  onLoadRoute: (route: SavedRoute) => void;
  lang: Language;
  onRoutesChanged?: () => void; // Callback for sync
}

export const SavedRoutesModal: React.FC<SavedRoutesModalProps> = ({ 
  isOpen, onClose, currentVisits, currentStart, currentReturn, onLoadRoute, lang, onRoutesChanged
}) => {
  const [savedRoutes, setSavedRoutes] = useState<SavedRoute[]>([]);
  const [newRouteName, setNewRouteName] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'save'>('list');
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const t = translations[lang];
  const { nodeRef, handleRef } = useDraggable<HTMLDivElement>(isOpen);

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        console.debug("Escape pressed in SavedRoutesModal");
        onClose();
      }
    };

    if (isOpen) {
      window.addEventListener('keydown', handleEsc, true); // Use capture to ensure priority
      loadRoutesFromStorage();
      setViewMode('list');
      setNewRouteName('');
      setDeletingId(null);
    }
    return () => window.removeEventListener('keydown', handleEsc, true);
  }, [isOpen, onClose]);

  const loadRoutesFromStorage = () => {
    try {
      const raw = localStorage.getItem('odocalc_saved_routes');
      if (raw) {
        setSavedRoutes(JSON.parse(raw));
      }
    } catch (e) {
      console.error("Failed to load saved routes", e);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newRouteName.trim()) return;

    const newRoute: SavedRoute = {
      id: Math.random().toString(36).substring(2, 9),
      name: newRouteName.trim(),
      createdAt: new Date().toISOString(),
      visits: currentVisits,
      startTrip: currentStart,
      returnTrip: currentReturn
    };

    const updatedRoutes = [...savedRoutes, newRoute];
    localStorage.setItem('odocalc_saved_routes', JSON.stringify(updatedRoutes));
    setSavedRoutes(updatedRoutes);
    setNewRouteName('');
    setViewMode('list');
    console.log(`Route "${newRouteName}" saved successfully.`);
    if (onRoutesChanged) onRoutesChanged();
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    e.preventDefault();

    if (deletingId === id) {
      const updatedRoutes = savedRoutes.filter(r => r.id !== id);
      localStorage.setItem('odocalc_saved_routes', JSON.stringify(updatedRoutes));
      setSavedRoutes(updatedRoutes);
      setDeletingId(null);
      console.log(`Route ${id} deleted permanently.`);
      if (onRoutesChanged) onRoutesChanged();
    } else {
      setDeletingId(id);
      setTimeout(() => {
        setDeletingId(prev => (prev === id ? null : prev));
      }, 4000);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[110] p-4">
      <div 
        ref={nodeRef}
        className="bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-lg p-6 animate-fade-in-up transition-colors max-h-[80vh] flex flex-col"
      >
        <div ref={handleRef} className="flex justify-between items-center mb-4 border-b border-gray-200 dark:border-gray-700 pb-2 select-none">
            <h3 className="text-xl font-bold text-gray-800 dark:text-white">
                {viewMode === 'list' ? t.savedRoutesTitle : t.saveRouteTitle}
            </h3>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
        </div>

        {viewMode === 'list' && (
          <div className="flex-grow overflow-y-auto min-h-[300px] pr-1">
            <div className="flex justify-between items-center mb-4">
               <p className="text-sm text-gray-500 dark:text-gray-400">
                   {savedRoutes.length === 0 ? t.noSavedRoutes : `${savedRoutes.length} ${t.routesFound}`}
               </p>
               <button 
                  onClick={() => setViewMode('save')}
                  disabled={currentVisits.length === 0}
                  className={`px-3 py-1.5 rounded-md text-sm font-medium flex items-center gap-2 transition-colors ${currentVisits.length === 0 ? 'bg-gray-100 text-gray-400 cursor-not-allowed' : 'bg-green-600 hover:bg-green-700 text-white'}`}
               >
                   <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                   {t.btnSaveCurrent}
               </button>
            </div>

            <div className="space-y-2">
                {savedRoutes.map(route => {
                    const isDeleting = deletingId === route.id;
                    return (
                        <div key={route.id} className={`bg-gray-50 dark:bg-gray-700/50 p-3 rounded-lg border transition-colors flex justify-between items-center group relative ${isDeleting ? 'border-red-500 bg-red-50 dark:bg-red-900/20' : 'border-gray-200 dark:border-gray-700 hover:border-google-blue dark:hover:border-blue-500'}`}>
                            <div onClick={() => { if(!isDeleting) { onLoadRoute(route); onClose(); } }} className={`cursor-pointer flex-grow ${isDeleting ? 'opacity-50 pointer-events-none' : ''}`}>
                                <h4 className={`font-bold transition-colors ${isDeleting ? 'text-red-600' : 'text-gray-800 dark:text-gray-200 group-hover:text-google-blue dark:group-hover:text-blue-400'}`}>
                                    {route.name}
                                </h4>
                                <div className="text-xs text-gray-500 dark:text-gray-400 flex items-center gap-2 mt-1">
                                    <span>{new Date(route.createdAt).toLocaleDateString()}</span>
                                    <span>•</span>
                                    <span>{route.visits.length} {t.stops}</span>
                                </div>
                            </div>
                            <div className="flex items-center gap-2">
                                {!isDeleting && (
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); onLoadRoute(route); onClose(); }}
                                        className="p-2 text-google-blue hover:bg-blue-50 dark:hover:bg-blue-900/30 rounded-full" 
                                        title={t.load}
                                    >
                                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
                                    </button>
                                )}
                                <button 
                                    onClick={(e) => handleDelete(e, route.id)}
                                    className={`p-2 rounded-full transition-all flex items-center justify-center min-w-[36px] min-h-[36px] ${isDeleting ? 'bg-red-600 text-white shadow-md scale-110' : 'text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30'}`}
                                    title={isDeleting ? t.confirm : t.delete}
                                >
                                    {isDeleting ? (
                                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                                        </svg>
                                    ) : (
                                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                        </svg>
                                    )}
                                </button>
                            </div>
                            {isDeleting && (
                                <div className="absolute inset-0 bg-red-600/5 rounded-lg flex items-center justify-center pointer-events-none">
                                    <span className="text-[10px] font-bold text-red-600 dark:text-red-400 uppercase tracking-widest translate-y-6">{t.confirm}</span>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
          </div>
        )}

        {viewMode === 'save' && (
            <form onSubmit={handleSave} className="flex flex-col gap-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t.lblRouteName}</label>
                    <input 
                        type="text" 
                        required
                        autoFocus
                        className="w-full border border-gray-300 dark:border-gray-600 rounded-md p-2 focus:ring-2 focus:ring-google-blue outline-none bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                        value={newRouteName}
                        onChange={e => setNewRouteName(e.target.value)}
                        placeholder="e.g. Pondělí - Hradec"
                    />
                </div>
                <div className="bg-blue-50 dark:bg-blue-900/20 p-3 rounded text-sm text-gray-600 dark:text-gray-300">
                    <p>{t.saveRouteDesc}</p>
                    <ul className="list-disc pl-5 mt-1 text-xs">
                        <li>{currentVisits.length} {t.stops}</li>
                        <li>{t.start}: {currentStart?.address || 'N/A'}</li>
                    </ul>
                </div>
                <div className="flex justify-end gap-2 mt-2">
                    <button 
                        type="button" 
                        onClick={() => setViewMode('list')}
                        className="px-4 py-2 text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-md"
                    >
                        {t.cancel}
                    </button>
                    <button 
                        type="submit"
                        className="px-4 py-2 bg-google-blue hover:bg-blue-700 text-white rounded-md font-medium shadow-sm"
                    >
                        {t.save}
                    </button>
                </div>
            </form>
        )}
      </div>
    </div>
  );
};

