        };

        if (editingItem) {
             setClients(prev => prev.map(c => c.id === editingItem.id ? { ...c, ...newClientData } : c));
        } else {
             setClients(prev => [...prev, { ...newClientData, id: uuid() }]);
        }
        // Sync Clients
        setTimeout(handleTriggerSync, 100);
