import { initializeApp, FirebaseApp, getApps } from "firebase/app";
import { getAuth, GoogleAuthProvider, signInWithPopup, signOut, User, Auth, onAuthStateChanged } from "firebase/auth";
import { getFirestore, doc, setDoc, getDoc, Firestore } from "firebase/firestore/lite";
import { BackupData } from "../types";

// --- HARDCODED CONFIGURATION ---
const firebaseConfig = {
  apiKey: "***REMOVED***",
  authDomain: "proj-visopt.firebaseapp.com",
  projectId: "proj-visopt",
  storageBucket: "proj-visopt.firebasestorage.app",
  messagingSenderId: "1048476373474",
  appId: "1:1048476373474:web:f629e9f83179f98970e9bb"
};

let app: FirebaseApp | undefined;
let auth: Auth | undefined;
let db: Firestore | undefined;

const COLLECTION = "localstorage";

// Initialize immediately
try {
    if (getApps().length > 0) {
        app = getApps()[0];
    } else {
        app = initializeApp(firebaseConfig);
    }

    auth = getAuth(app);
    db = getFirestore(app);
    console.log("[Cloud] Firebase initialized");
} catch (e) {
    console.error("[Cloud] Firebase Initialization Failed. Check services/firebaseService.ts config.", e);
}

export const FirebaseService = {

  isConfigured: () => {
      return !!auth && !!db;
  },

  /**
   * Subscribe to auth state changes safely.
   */
  subscribeAuth: (callback: (user: User | null) => void) => {
      if (!auth) {
          console.warn("[Cloud] Subscribe attempted before initialization or invalid config");
          return () => {};
      }
      return onAuthStateChanged(auth, callback);
  },

  signIn: async () => {
    if (!auth) throw new Error("Firebase not initialized. Check console for errors.");
    const provider = new GoogleAuthProvider();
    try {
      await signInWithPopup(auth, provider);
    } catch (error: any) {
      console.error("Firebase Sign In Error", error);
      throw new Error(error.message || "Sign in failed");
    }
  },

  signOut: async () => {
    if (!auth) return;
    try {
      await signOut(auth);
    } catch (error) {
      console.error("Firebase Sign Out Error", error);
    }
  },

  /**
   * Syncs local data to Firestore (Upload)
   */
  syncUp: async (user: User) => {
    if (!user || !user.email || !db) return;

    try {
      const clients = JSON.parse(localStorage.getItem('odocalc_db_clients') || '[]');
      const settings = JSON.parse(localStorage.getItem('odocalc_settings') || '{}');
      const savedRoutes = JSON.parse(localStorage.getItem('odocalc_saved_routes') || '[]');
      const lmod = JSON.parse(localStorage.getItem('odocalc_lmod') || '{}');

      const payload: BackupData = {
        clients,
        settings,
        savedRoutes,
        lmod,
        timestamp: Date.now()
      };

      await setDoc(doc(db, COLLECTION, user.email), payload);

      // Update local tracking timestamp
      localStorage.setItem('odocalc_last_modified', payload.timestamp.toString());

      console.log(`[Cloud] Synced UP successfully for ${user.email}`);
    } catch (e) {
      console.error("[Cloud] Sync UP failed", e);
      throw e;
    }
  },

  /**
   * Syncs Cloud data to Local (Download)
   * Returns true if data was updated, false otherwise.
   */
  syncDown: async (user: User): Promise<{ updated: boolean, data?: BackupData }> => {
    if (!user || !user.email || !db) return { updated: false };

    try {
      const docRef = doc(db, COLLECTION, user.email);
      const docSnap = await getDoc(docRef);

      if (docSnap.exists()) {
        const cloudData = docSnap.data() as BackupData;
        const localTs = parseInt(localStorage.getItem('odocalc_last_modified') || '0');

        console.log(`[Cloud] Timestamp Check - Local: ${localTs}, Cloud: ${cloudData.timestamp}`);

        // If Cloud is newer than Local, overwrite Local
        if (cloudData.timestamp > localTs) {
          localStorage.setItem('odocalc_db_clients', JSON.stringify(cloudData.clients || []));
          localStorage.setItem('odocalc_settings', JSON.stringify(cloudData.settings || {}));
          localStorage.setItem('odocalc_saved_routes', JSON.stringify(cloudData.savedRoutes || []));
          localStorage.setItem('odocalc_lmod', JSON.stringify(cloudData.lmod || {}));
          localStorage.setItem('odocalc_last_modified', cloudData.timestamp.toString());

          console.log(`[Cloud] Synced DOWN successfully. Local updated.`);
          return { updated: true, data: cloudData };
        }
      }
    } catch (e) {
      console.error("[Cloud] Sync DOWN failed", e);
      throw e;
    }
    return { updated: false };
  }
};

const handleOptimizeRoute = async () => {
    if (!isApiReady) return;

    // Determine the set of visits to optimize
    // 1. If user has selected specific rows, optimize ONLY those.
    // 2. If no rows selected, optimize ALL active (not skipped) rows.
    let targetVisits = visits.filter(v => !v.isSkipped);

    if (selectedIds.size > 0) {
        targetVisits = visits.filter(v => selectedIds.has(v.id));
    }

    // Check if we have enough points (Start + at least 1 visit)
    if (targetVisits.length < 1) {
         setErrorMsg("Not enough visits selected for optimization.");
         return;
    }
    if (!settings.startAddress) return;

    setCalcStatus(CalculationStatus.ROUTING);
    setErrorMsg(null);
    setProgress({ current: 0, total: 100, message: 'Checking cached distances...' });

    try {
        // Ensure we have matrix data for start address and all targets
        const allAddresses = [settings.startAddress, ...targetVisits.map(v => v.address)];
        await ensureMatrixData(allAddresses, (msg) => { setProgress(prev => ({ ...prev, message: msg })); });

        setProgress({ current: 90, total: 100, message: 'Solving TSP...' });
        await sleep(100);

        // Solve TSP only for the target visits
        const optimizedSequence = solveTSP(settings.startAddress, targetVisits);

        // Reconstruct the full list:
        // We need to keep non-target visits (e.g. unselected ones) in the list, 
        // but we might need to decide where to put them. 
        // Strategy: Put optimized ones at the top (or replace their positions), keep others at bottom or relative.
        // Simplest strategy: Optimized ones first (reordered), followed by the rest (unchanged relative order).

        const targetIds = new Set(targetVisits.map(v => v.id));
        const remainingVisits = visits.filter(v => !targetIds.has(v.id));

        // Combine: Optimized Selection + Rest
        const newOrder = [...optimizedSequence, ...remainingVisits];

        const reindexed = reindexVisits(clearCalculation(newOrder));
        setVisits(reindexed);

        // Automatically calculate metrics for the new order (only for the active ones within the new order)
        // Note: runCalculation filters out skipped items internally
        await runCalculation(reindexed, false);

        console.log(`Route optimized successfully. (${targetVisits.length} items)`);
    } catch (err: any) { 
        console.error(err); 
        setErrorMsg(`${t.msgOptFail}: ${err.message}`); 
        setCalcStatus(CalculationStatus.ERROR); 
    }
};

import React, { useState, useEffect } from 'react';
import { 
  Visit, Client, AppSettings, SavedRoute, StartTrip, ReturnTrip, 
  CalculationStatus, VisitRepetition, BackupData 
} from './types';
import { VisitList } from './components/VisitList';
import { VisitModal } from './components/VisitModal';
import { SettingsModal } from './components/SettingsModal';
import { MapSection } from './components/MapModal';
import { SavedRoutesModal } from './components/SavedRoutesModal';
import { ClientDbModal } from './components/ClientDbModal';
import { HelpModal } from './components/HelpModal';
import { 
  ensureMatrixData, getRouteData, loadGoogleMapsScript, setRuntimeApiKey 
} from './services/googleMapsService';
import { setCacheExpirationDays } from './services/distanceCache';
import { solveTSP } from './services/tspSolver';
import { parseVisitsExcel } from './services/excelService';
import { translations } from './services/translations';
import { FirebaseService } from './services/firebaseService';
import { isClientScheduledForDate, sortVisitsByTime } from './services/scheduler';

// Helper for unique IDs
const generateId = () => Math.random().toString(36).substring(2, 9);
const sleep = (ms: number) => new Promise(r => setTimeout(r, ms));

// Default Settings
const DEFAULT_SETTINGS: AppSettings = {
  startAddress: '',
  currentOdometer: 0,
  departureTime: '08:00:00',
  isStrictMode: false,
  isDarkMode: false,
  cacheExpirationDays: 30,
  language: 'cs'
};

function App() {
  // State
  const [visits, setVisits] = useState<Visit[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);

  const [startTrip, setStartTrip] = useState<StartTrip | null>(null);
  const [returnTrip, setReturnTrip] = useState<ReturnTrip | null>(null);

  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [calcStatus, setCalcStatus] = useState<CalculationStatus>(CalculationStatus.IDLE);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [progress, setProgress] = useState({ current: 0, total: 100, message: '' });

  const [isApiReady, setIsApiReady] = useState(false);
  const [user, setUser] = useState<any>(null); // Firebase User

  // Modals state
  const [modals, setModals] = useState({
    visit: false,
    client: false,
    settings: false,
    map: false,
    savedRoutes: false,
    clientDb: false,
    help: false
  });

  const [editingItem, setEditingItem] = useState<Visit | Client | null>(null);

  const t = translations[settings.language];

  // --- Initialization & Persistance ---

  useEffect(() => {
    // Load from LocalStorage on mount
    const storedSettings = localStorage.getItem('odocalc_settings');
    if (storedSettings) setSettings({ ...DEFAULT_SETTINGS, ...JSON.parse(storedSettings) });

    const storedClients = localStorage.getItem('odocalc_db_clients');
    if (storedClients) setClients(JSON.parse(storedClients));

    // Auth Listener
    const unsubscribe = FirebaseService.subscribeAuth((u) => {
        setUser(u);
        if (u) FirebaseService.syncDown(u).then(res => {
            if (res.updated && res.data) {
                 if (res.data.settings) setSettings(res.data.settings);
                 if (res.data.clients) setClients(res.data.clients);
                 window.location.reload(); // Simple reload to apply all changes (e.g. LMOD)
            }
        });
    });

    return () => unsubscribe();
  }, []);

  // Save Settings & Clients on change
  useEffect(() => {
    localStorage.setItem('odocalc_settings', JSON.stringify(settings));
    if (settings.googleApiKey) {
        setRuntimeApiKey(settings.googleApiKey);
        loadGoogleMapsScript(settings.googleApiKey)
            .then(() => setIsApiReady(true))
            .catch(() => setIsApiReady(false));
    }
    if (settings.cacheExpirationDays) {
        setCacheExpirationDays(settings.cacheExpirationDays);
    }

    // Theme
    if (settings.isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');

  }, [settings]);

  useEffect(() => {
    localStorage.setItem('odocalc_db_clients', JSON.stringify(clients));
  }, [clients]);

  // --- Logic Helpers ---

  const reindexVisits = (list: Visit[]): Visit[] => {
      return list.map((v, idx) => ({ ...v, order: idx + 1 }));
  };

  const clearCalculation = (list: Visit[]): Visit[] => {
      return list.map(v => {
          const { segmentDistance, exactDistanceKm, segmentDuration, arrivalTime, totalOdometer, ...rest } = v;
          return rest as Visit;
      });
  };

  // --- Core Calculation Logic ---

  const runCalculation = async (currentVisits: Visit[], strictMode: boolean = false) => {
      if (!settings.startAddress) {
          setErrorMsg(t.msgStartReq);
          return;
      }
      if (currentVisits.length === 0) {
          setStartTrip(null);
          setReturnTrip(null);
          return;
      }

      setCalcStatus(CalculationStatus.ROUTING);
      setErrorMsg(null);
      setProgress({ current: 0, total: 100, message: t.msgRouting + '...' });

      // 1. Prepare Start
      const start: StartTrip = {
          address: settings.startAddress,
          odometer: settings.currentOdometer
      };

      const calculatedVisits: Visit[] = [];
      let currentAddr = start.address;
      let currentOdo = start.odometer;

      // Parse departure time
      const [depH, depM] = settings.departureTime.split(':').map(Number);
      let currentTimeSeconds = depH * 3600 + depM * 60; // seconds from midnight

      try {
          const activeVisits = currentVisits.filter(v => !v.isSkipped);

          for (let i = 0; i < activeVisits.length; i++) {
              const visit = activeVisits[i];
              setProgress({ current: i, total: activeVisits.length, message: `${t.msgRouting} ${visit.surname}` });

              const result = await getRouteData(currentAddr, visit.address);

              // Accumulate
              currentOdo += parseFloat(result.distanceKm.toFixed(1)); // Rounded logic for odometer matching user expectations usually
              currentTimeSeconds += result.durationSeconds; // Travel time

              // Arrival Time String
              const arrH = Math.floor(currentTimeSeconds / 3600) % 24;
              const arrM = Math.floor((currentTimeSeconds % 3600) / 60);
              const arrivalTimeStr = `${arrH.toString().padStart(2,'0')}:${arrM.toString().padStart(2,'0')}`;

              // Add Service Time
              currentTimeSeconds += (visit.visitDuration * 60);

              calculatedVisits.push({
                  ...visit,
                  segmentDistance: parseFloat(result.distanceKm.toFixed(1)),
                  exactDistanceKm: result.distanceKm,
                  segmentDuration: result.durationSeconds,
                  arrivalTime: arrivalTimeStr,
                  totalOdometer: parseFloat(currentOdo.toFixed(1))
              });

              currentAddr = visit.address;
          }

          // Merge calculated active visits back into the full list (preserving skipped ones)
          const finalVisits = currentVisits.map(v => {
              if (v.isSkipped) return v;
              const calc = calculatedVisits.find(cv => cv.id === v.id);
              return calc || v;
          });

          setVisits(finalVisits);
          setStartTrip(start);

          // Return Trip
          if (activeVisits.length > 0) {
             setProgress({ current: 100, total: 100, message: t.msgCalcReturn });
             const lastVisit = activeVisits[activeVisits.length - 1];
             const retRes = await getRouteData(lastVisit.address, start.address);

             currentTimeSeconds += retRes.durationSeconds;
             const arrH = Math.floor(currentTimeSeconds / 3600) % 24;
             const arrM = Math.floor((currentTimeSeconds % 3600) / 60);

             setReturnTrip({
                 address: start.address,
                 segmentDistance: parseFloat(retRes.distanceKm.toFixed(1)),
                 exactDistanceKm: retRes.distanceKm,
                 segmentDuration: retRes.durationSeconds,
                 arrivalTime: `${arrH.toString().padStart(2,'0')}:${arrM.toString().padStart(2,'0')}`,
                 totalOdometer: parseFloat((currentOdo + parseFloat(retRes.distanceKm.toFixed(1))).toFixed(1))
             });
          }

          setCalcStatus(CalculationStatus.COMPLETE);
      } catch (err: any) {
          console.error(err);
          setErrorMsg(err.toString());
          setCalcStatus(CalculationStatus.ERROR);
      }
  };

  // --- Handlers ---

  const handleOptimizeRoute = async () => {
      if (!isApiReady) {
          setErrorMsg(t.msgApiMissing);
          return;
      }

      let targetVisits = visits.filter(v => !v.isSkipped);
      if (selectedIds.size > 0) {
          targetVisits = visits.filter(v => selectedIds.has(v.id));
      }

      if (targetVisits.length < 1) {
           setErrorMsg(t.msgNoActive);
           return;
      }
      if (!settings.startAddress) {
          setErrorMsg(t.msgStartReq);
          return;
      }

      setCalcStatus(CalculationStatus.ROUTING);
      setErrorMsg(null);
      setProgress({ current: 0, total: 100, message: 'Checking cached distances...' });

      try {
          const allAddresses = [settings.startAddress, ...targetVisits.map(v => v.address)];
          await ensureMatrixData(allAddresses, (msg) => { setProgress(prev => ({ ...prev, message: msg })); });

          setProgress({ current: 90, total: 100, message: 'Solving TSP...' });
          await sleep(100);

          const optimizedSequence = solveTSP(settings.startAddress, targetVisits);

          // Strategy: Selected visits are reordered at the top, unselected/skipped remain at bottom (or relative)
          const targetIds = new Set(targetVisits.map(v => v.id));
          const remainingVisits = visits.filter(v => !targetIds.has(v.id));

          const newOrder = [...optimizedSequence, ...remainingVisits];
          const reindexed = reindexVisits(clearCalculation(newOrder));
          setVisits(reindexed);

          await runCalculation(reindexed, false);
      } catch (err: any) { 
          console.error(err); 
          setErrorMsg(`${t.msgOptFail}: ${err.message}`); 
          setCalcStatus(CalculationStatus.ERROR); 
      }
  };

  const handleCalculate = () => {
      runCalculation(visits, settings.isStrictMode);
  };

  const handleImportExcel = async (file: File) => {
      try {
          const data = await parseVisitsExcel(file);
          const newVisits = data.map((d, i) => ({
              ...d,
              id: generateId(),
              order: visits.length + i + 1,
              visitDuration: d.visitDuration || 30
          }));
          const updated = [...visits, ...newVisits];
          setVisits(reindexVisits(updated));
      } catch (e: any) {
          alert(e.message);
      }
  };

  const handleClientImportExcel = async (file: File) => {
      try {
          const data = await parseVisitsExcel(file);
          // Convert to Clients
          const newClients: Client[] = data.map(d => ({
              id: generateId(),
              name: d.name,
              surname: d.surname,
              address: d.address,
              defaultDuration: d.visitDuration || 30,
              visitRepetition: { type: 'WEEKLY', daysOfWeek: [] }
          }));
          setClients(prev => [...prev, ...newClients]);
      } catch (e: any) {
          alert(e.message);
      }
  };

  const handleAddVisit = (data: any) => {
      const newVisit: Visit = {
          id: generateId(),
          ...data,
          order: visits.length + 1
      };
      setVisits(reindexVisits([...visits, newVisit]));
  };

  const handleEditVisit = (data: any) => {
      if (!editingItem) return;
      const updatedVisits = visits.map(v => v.id === editingItem.id ? { ...v, ...data } : v);
      setVisits(clearCalculation(updatedVisits)); // Clear calc on edit
  };

  const handleAddClient = (data: Omit<Client, 'id'>) => {
      setClients([...clients, { ...data, id: generateId() }]);
  };

  const handleEditClient = (data: any) => {
      if (!editingItem) return;
      setClients(clients.map(c => c.id === editingItem.id ? { ...c, ...data } : c));
  };

  const handleDelete = (id: string) => {
      setVisits(reindexVisits(visits.filter(v => v.id !== id)));
      setSelectedIds(prev => {
          const next = new Set(prev);
          next.delete(id);
          return next;
      });
  };

  const handleReorder = (newVisits: Visit[]) => {
      setVisits(reindexVisits(newVisits));
      // Optionally clear calculation or just let user re-calc
      setVisits(prev => clearCalculation(prev)); 
  };

  const handleToggleSkip = (id: string) => {
      setVisits(prev => prev.map(v => v.id === id ? { ...v, isSkipped: !v.isSkipped } : v));
  };

  const handleLoadPlan = () => {
      if (visits.length > 0) {
          if (!confirm(t.msgConfirmPlanReload)) return;
      }

      const today = new Date();
      // Filter clients scheduled for today
      const scheduledClients = clients.filter(c => isClientScheduledForDate(c, today));

      // Convert to Visits
      let planVisits: Visit[] = scheduledClients.map(c => ({
          id: generateId(),
          name: c.name,
          surname: c.surname,
          address: c.address,
          order: 0, // Will sort
          visitDuration: c.defaultDuration,
          preferredTime: c.visitStartAt
      }));

      // Sort by preferred time
      planVisits = sortVisitsByTime(planVisits);
      setVisits(reindexVisits(planVisits));
      alert(`${t.msgPlanReloaded} (${planVisits.length} visits)`);
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${settings.isDarkMode ? 'dark bg-gray-900' : 'bg-gray-100'}`}>
      <div className="container mx-auto p-2 sm:p-4 max-w-7xl">

        {/* Top Bar */}
        <div className="flex flex-col sm:flex-row justify-between items-center mb-6 bg-white dark:bg-gray-800 p-4 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700">
             <div className="flex items-center gap-3 mb-3 sm:mb-0">
                 <div className="w-10 h-10 bg-google-blue rounded-lg flex items-center justify-center text-white font-bold text-xl shadow-lg">V</div>
                 <div>
                    <h1 className="text-2xl font-bold text-gray-800 dark:text-white leading-none">{t.appTitle}</h1>
                    <p className="text-xs text-gray-500 dark:text-gray-400">{t.subTitle}</p>
                 </div>
             </div>

             <div className="flex items-center gap-2">
                 <button onClick={() => setModals({...modals, help: true})} className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full" title={t.helpTitle}>
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                 </button>
                 <button onClick={() => setModals({...modals, savedRoutes: true})} className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full" title={t.savedRoutes}>
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 19a2 2 0 01-2-2V7a2 2 0 012-2h4l2 2h4a2 2 0 012 2v1M5 19h14a2 2 0 002-2v-5a2 2 0 00-2-2H9a2 2 0 00-2 2v5a2 2 0 01-2 2z" /></svg>
                 </button>

                 {/* Cloud Auth */}
                 {user ? (
                     <button onClick={() => FirebaseService.signOut()} className="p-2 text-green-600 bg-green-50 dark:bg-green-900/20 rounded-full" title={`Logged in as ${user.email}`}>
                        <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>
                     </button>
                 ) : (
                     <button onClick={() => FirebaseService.signIn()} className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full" title="Cloud Sync Login">
                        <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 15a4 4 0 004 4h9a5 5 0 10-.1-9.999 5.002 5.002 0 10-9.78 2.096A4.001 4.001 0 003 15z" /></svg>
                     </button>
                 )}

                 <div className="h-6 w-px bg-gray-300 dark:bg-gray-600 mx-2"></div>

                 <button onClick={() => setModals({...modals, settings: true})} className="flex items-center gap-2 px-3 py-2 bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 rounded-md transition-colors text-sm font-medium text-gray-700 dark:text-gray-200">
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                    <span className="hidden sm:inline">{t.settingsTitle}</span>
                    {!isApiReady && <span className="w-2 h-2 rounded-full bg-red-500 animate-pulse" title={t.keyMissing}></span>}
                 </button>
             </div>
        </div>

        {/* Actions Toolbar */}
        <div className="flex flex-wrap gap-2 mb-4 bg-white dark:bg-gray-800 p-3 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700">
             <button onClick={() => { setEditingItem(null); setModals({...modals, visit: true}); }} className="px-4 py-2 bg-google-blue hover:bg-blue-700 text-white rounded-md font-bold shadow-sm flex items-center gap-2 transition-transform active:scale-95">
                 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                 {t.newVisit}
             </button>

             <button onClick={() => setModals({...modals, clientDb: true})} className="px-4 py-2 bg-orange-600 hover:bg-orange-700 text-white rounded-md font-bold shadow-sm flex items-center gap-2 transition-transform active:scale-95">
                 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
                 {t.clientDb}
             </button>

             <button onClick={handleLoadPlan} className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-md font-bold shadow-sm flex items-center gap-2 transition-transform active:scale-95">
                 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                 {t.importPlan}
             </button>

             <button onClick={() => document.getElementById('visit-file-input')?.click()} className="px-4 py-2 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-200 hover:bg-gray-50 dark:hover:bg-gray-600 rounded-md font-bold shadow-sm flex items-center gap-2 transition-transform active:scale-95">
                 <input type="file" id="visit-file-input" accept=".xlsx" className="hidden" onChange={(e) => e.target.files && handleImportExcel(e.target.files[0])} />
                 <svg className="w-5 h-5 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                 {t.importExcel}
             </button>

             <div className="w-px h-8 bg-gray-300 dark:bg-gray-600 mx-1 self-center"></div>

             <button onClick={handleOptimizeRoute} disabled={calcStatus === CalculationStatus.ROUTING} className="px-4 py-2 bg-teal-600 hover:bg-teal-700 text-white rounded-md font-bold shadow-sm flex items-center gap-2 transition-transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed">
                 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                 {t.optimal}
             </button>

             <button onClick={handleCalculate} disabled={calcStatus === CalculationStatus.ROUTING} className="px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded-md font-bold shadow-sm flex items-center gap-2 transition-transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed">
                 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 7h6m0 10v-3m-3 3h.01M9 17h.01M9 14h.01M12 14h.01M15 11h.01M12 11h.01M9 11h.01M7 21h10a2 2 0 002-2V5a2 2 0 00-2-2H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg>
                 {t.calculate}
             </button>

             <button onClick={() => setModals({...modals, map: !modals.map})} className={`px-4 py-2 border rounded-md font-bold shadow-sm flex items-center gap-2 transition-transform active:scale-95 ${modals.map ? 'bg-gray-200 dark:bg-gray-700 text-gray-800 dark:text-gray-200' : 'bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-200 hover:bg-gray-50'}`}>
                 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 20l-5.447-2.724A1 1 0 013 16.382V5.618a1 1 0 011.447-.894L9 7m0 13l6-3m-6 3V7m6 10l4.553 2.276A1 1 0 0021 18.382V7.618a1 1 0 00-.553-.894L15 4m0 13V4m0 0L9 7" /></svg>
                 {modals.map ? t.hideMap : t.visualize}
             </button>
        </div>

        {/* Progress Bar */}
        {calcStatus === CalculationStatus.ROUTING && (
            <div className="mb-4 bg-white dark:bg-gray-800 rounded-lg p-3 shadow-sm border border-blue-100 dark:border-blue-900">
                <div className="flex justify-between text-xs font-bold text-blue-600 dark:text-blue-400 mb-1">
                    <span>{progress.message}</span>
                    <span>{Math.round((progress.current / progress.total) * 100)}%</span>
                </div>
                <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2">
                    <div className="bg-blue-600 h-2 rounded-full transition-all duration-300" style={{ width: `${(progress.current / progress.total) * 100}%` }}></div>
                </div>
            </div>
        )}

        {/* Error Message */}
        {errorMsg && (
            <div className="mb-4 bg-red-100 dark:bg-red-900/30 border-l-4 border-red-500 text-red-700 dark:text-red-300 p-4 rounded shadow-sm flex justify-between items-center">
                <div className="flex items-center gap-2">
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                    <p className="font-medium">{errorMsg}</p>
                </div>
                <button onClick={() => setErrorMsg(null)} className="text-red-500 hover:text-red-700 font-bold">✕</button>
            </div>
        )}

        {/* Map Section */}
        <MapSection 
            isOpen={modals.map} 
            onClose={() => setModals({...modals, map: false})} 
            startTrip={startTrip} 
            visits={visits}
            lang={settings.language}
        />

        {/* Visits List */}
        <VisitList 
            visits={visits}
            startTrip={startTrip}
            returnTrip={returnTrip}
            selectedIds={selectedIds}
            onToggleSelect={(id) => {
                const newSet = new Set(selectedIds);
                if (newSet.has(id)) newSet.delete(id);
                else newSet.add(id);
                setSelectedIds(newSet);
            }}
            onToggleAll={(checked) => setSelectedIds(checked ? new Set(visits.map(v => v.id)) : new Set())}
            onEdit={(v) => { setEditingItem(v); setModals({...modals, visit: true}); }}
            onReorder={handleReorder}
            onToggleSkip={handleToggleSkip}
            onDelete={handleDelete}
            lang={settings.language}
            departureTime={settings.departureTime}
        />

        {/* Modals */}
        <VisitModal 
            isOpen={modals.visit && !modals.client} 
            onClose={() => setModals({...modals, visit: false})}
            onSave={(data) => editingItem ? handleEditVisit(data) : handleAddVisit(data)}
            initialData={editingItem}
            lang={settings.language}
            mode="visit"
        />

        <SettingsModal 
            isOpen={modals.settings}
            onClose={() => setModals({...modals, settings: false})}
            settings={settings}
            onSave={(newSettings) => {
                setSettings(newSettings);
            }}
        />

        <SavedRoutesModal 
            isOpen={modals.savedRoutes}
            onClose={() => setModals({...modals, savedRoutes: false})}
            currentVisits={visits}
            currentStart={startTrip}
            currentReturn={returnTrip}
            onLoadRoute={(route) => {
                setVisits(route.visits);
                setStartTrip(route.startTrip || null);
                setReturnTrip(route.returnTrip || null);
            }}
            lang={settings.language}
            onRoutesChanged={() => {
                if (user) FirebaseService.syncUp(user);
            }}
        />

        <ClientDbModal
            isOpen={modals.clientDb}
            onClose={() => setModals({...modals, clientDb: false})}
            clients={clients}
            onAddClient={handleAddClient}
            onEditClient={(c) => { setEditingItem(c); setModals({...modals, clientDb: false, visit: true, client: true}); }}
            onDeleteClient={(id) => setClients(clients.filter(c => c.id !== id))}
            onDeleteClients={(ids) => setClients(clients.filter(c => !ids.has(c.id)))}
            onValidateClients={async (ids) => {
                 // Validation stub
                 console.log("Validating", ids);
            }}
            onAddToRoute={(selected) => {
                const newVisits = selected.map(c => ({
                    id: generateId(),
                    name: c.name,
                    surname: c.surname,
                    address: c.address,
                    order: visits.length + 1, 
                    visitDuration: c.defaultDuration,
                    preferredTime: c.visitStartAt,
                    isAddressValid: c.isAddressValid
                }));
                const updated = [...visits, ...newVisits];
                setVisits(reindexVisits(updated));
                alert(`${selected.length} ${t.msgAddedToRoute}`);
                setModals({...modals, clientDb: false});
            }}
            onImportExcel={handleClientImportExcel}
            lang={settings.language}
        />

        {/* Reuse VisitModal for Clients (using mode='client') */}
        {modals.client && (
            <VisitModal 
                isOpen={modals.visit} 
                onClose={() => { setModals({...modals, visit: false, client: false, clientDb: true}); }} 
                onSave={(data) => {
                    editingItem ? handleEditClient(data) : handleAddClient(data);
                    setModals({...modals, visit: false, client: false, clientDb: true});
                }}
                initialData={editingItem}
                lang={settings.language}
                mode="client"
            />
        )}

        <HelpModal 
            isOpen={modals.help}
            onClose={() => setModals({...modals, help: false})}
            lang={settings.language}
            onLoadSampleData={(data) => {
                 const newVisits = data.map((d, i) => ({
                    id: generateId(),
                    ...d,
                    order: i + 1
                 }));
                 setVisits(newVisits);
                 setSettings(prev => ({ ...prev, startAddress: 'Pardubice, Třída Míru 1' }));
            }}
        />

      </div>
    </div>
  );
}

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './index.css';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);
